import torch
import torch.nn as nn
from torch.utils.cpp_extension import load_inline

# CUDA code for matrix multiplication and element-wise comparison
source = """
#include <cublas_v2.h>
#include <ATen/cuda/CUDAContext.h>
#include <torch/extension.h>

__global__ void ge_kernel(const float *mat, const float *bias, bool *output, int B, int H) {
    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    if (idx < B * H) {
        int col = idx % H;
        output[idx] = mat[idx] >= bias[col];
    }
}

torch::Tensor mm_cuda(torch::Tensor x, torch::Tensor weight) {
    int B = x.size(0);
    int I = x.size(1);
    int H = weight.size(1);

    auto output = torch::empty({B, H}, x.options());

    cublasHandle_t handle = at::cuda::getCurrentCUDABlasHandle();
    cublasSetStream(handle, at::cuda::getCurrentCUDAStream());

    float alpha = 1.0f;
    float beta = 0.0f;

    cublasSgemm(
        handle,
        CUBLAS_OP_N,
        CUBLAS_OP_N,
        H,
        B,
        I,
        &alpha,
        weight.data_ptr<float>(),
        H,
        x.data_ptr<float>(),
        I,
        &beta,
        output.data_ptr<float>(),
        H
    );

    return output;
}

torch::Tensor ge_cuda(torch::Tensor mat, torch::Tensor bias) {
    int B = mat.size(0);
    int H = mat.size(1);

    auto output = torch::empty({B, H}, mat.options().dtype(torch::kBool));

    int num_elements = B * H;
    int threads = 256;
    int blocks = (num_elements + threads - 1) / threads;

    ge_kernel<<<blocks, threads>>>(
        mat.data_ptr<float>(),
        bias.data_ptr<float>(),
        output.data_ptr<bool>(),
        B,
        H
    );

    return output;
}
"""

