import torch


class Model(torch.nn.Module):
    def __init__(self, shape1, shape2, shape3):
        super().__init__()
        self.tensor1 = torch.nn.Parameter(torch.randn(shape1))
        self.tensor2 = torch.nn.Parameter(torch.randn(shape2))
        self.tensor3 = torch.nn.Parameter(torch.randn(shape3))

    def forward(self, x):
        x = torch.eq(x, self.tensor1)
        x = torch.multiply(x, self.tensor2)
        x = torch.multiply(x, self.tensor3)
        return x


