import torch
import torch.nn as nn
from torch.utils.cpp_extension import load_inline

# CUDA kernel for fused equality check and element-wise multiplication
source = """
#include <torch/extension.h>

__global__ void fused_eq_multiply_kernel(
    const float* x, 
    const float* tensor1,
    const float* tensor2,
    const float* tensor3,
    float* output,
    int num_elements
) {
    const int idx = blockIdx.x * blockDim.x + threadIdx.x;
    if (idx < num_elements) {
        float x_val = x[idx];
        float t1_val = tensor1[idx];
        float mask = (x_val == t1_val) ? 1.0f : 0.0f;
        output[idx] = mask * tensor2[idx] * tensor3[idx];
    }
}

torch::Tensor fused_eq_multiply_cuda(
    torch::Tensor x,
    torch::Tensor tensor1,
    torch::Tensor tensor2,
    torch::Tensor tensor3
) {
