#include <torch/extension.h>

__global__ void glu_kernel(const float *input, float *output, int in_features, int batch_size, int input_channels, int seq_length,
                           int64_t input_stride_batch, int64_t input_stride_channel, int64_t input_stride_seq,
                           int64_t output_stride_batch, int64_t output_stride_channel, int64_t output_stride_seq) {
    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    if (idx >= batch_size * in_features * seq_length) return;

    int b = idx / (in_features * seq_length);
    int rem = idx % (in_features * seq_length);
    int i = rem / seq_length;
    int s = rem % seq_length;

    int input_idx1 = b * input_stride_batch + i * input_stride_channel + s * input_stride_seq;
    int input_idx2 = b * input_stride_batch + (i + in_features) * input_stride_channel + s * input_stride_seq;

    float x1 = input[input_idx1];
    float x2 = input[input_idx2];
    float sigmoid_x2 = 1.0f / (1.0f + expf(-x2));
    output[b * output_stride_batch + i * output_stride_channel + s * output_stride_seq] = x1 * sigmoid_x2;
}

