# Define the fused permute and XOR CUDA kernel
source = """
#include <torch/extension.h>
#include <cuda.h>
#include <cuda_runtime.h>

__global__ void permute_xor_kernel(const uint8_t* input, uint8_t* output,
                                    int N, int C, int H, int W) {
    const int total = N * H * W * C;
    for (int idx = blockIdx.x * blockDim.x + threadIdx.x;
         idx < total;
         idx += blockDim.x * gridDim.x) {
        // Calculate n, h, w, c from linear index
        int n = idx / (H * W * C);
        int rem = idx % (H * W * C);
        int h = rem / (W * C);
        rem %= (W * C);
        int w = rem / C;
        int c = rem % C;

        // Calculate previous h index with wrap-around
        int h_prev = (h == 0) ? H - 1 : h - 1;

        // Input indices (N, C, H, W layout)
        int in_idx1 = n*C*H*W + c*H*W + h*W + w;
        int in_idx2 = n*C*H*W + c*H*W + h_prev*W + w;

        // Output index (N, H, W, C layout)
        int out_idx = n*H*W*C + h*W*C + w*C + c;

        output[out_idx] = input[in_idx1] ^ input[in_idx2];
    }
}

torch::Tensor permute_xor_cuda(torch::Tensor input) {
    TORCH_CHECK(input.dim() == 4, "Input must be 4D tensor");
    auto sizes = input.sizes();
    int N = sizes[0], C = sizes[1], H = sizes[2], W = sizes[3];

    auto output = torch::empty({N, H, W, C}, input.options());

    const int block_size = 256;
    int total_elements = N * H * W * C;
    int grid_size = (total_elements + block_size - 1) / block_size;

    permute_xor_kernel<<<grid_size, block_size>>>(
        input.data_ptr<uint8_t>(),
        output.data_ptr<uint8_t>(),
        N, C, H, W
    );

    return output;
}
