# CUDA kernel for fused ReLU and logsumexp along dim=1
source = """
#include <torch/extension.h>

__global__ void relu_logsumexp_kernel(const float* input, float* output, int B, int C, int H, int W) {
    int b = blockIdx.x;
    int h = blockIdx.y * blockDim.y + threadIdx.y;
    int w = blockIdx.z * blockDim.z + threadIdx.z;

    if (b >= B || h >= H || w >= W) return;

    float max_val = -INFINITY;
    for (int c = 0; c < C; ++c) {
        float val = input[((b * C + c) * H + h) * W + w];
        val = fmaxf(val, 0.0f);
        max_val = fmaxf(max_val, val);
    }

    float sum_exp = 0.0f;
    for (int c = 0; c < C; ++c) {
        float val = input[((b * C + c) * H + h) * W + w];
        val = fmaxf(val, 0.0f);
        sum_exp += expf(val - max_val);
    }

    output[b * H * W + h * W + w] = logf(sum_exp) + max_val;
}

torch::Tensor relu_logsumexp_cuda(torch::Tensor input, int dim) {
    TORCH_CHECK(dim == 1, "logsumexp dimension must be 1");
    const int B = input.size(0);
    const int C = input.size(1);
    const int H = input.size(2);
    const int W = input.size(3);
    torch::Tensor output = torch::empty({B, H, W}, input.options());

    dim3 block(1, 16, 16);  // Threads per block for h and w dimensions
    dim3 grid(B, (H + block.y - 1) / block.y, (W + block.z - 1) / block.z);

    relu_logsumexp_kernel<<<grid, block>>>(
        input.contiguous().data_ptr<float>(),
        output.data_ptr<float>(),
        B, C, H, W
    );

    return output;
}
