__global__ void glu_softmax_kernel(const float* input, float* output, int N, int H, int W) {
    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    if (idx >= N * H * W) return;

    int n = idx / (H * W);
    int hw = idx % (H * W);
    int h = hw / W;
    int w = hw % W;

    float x1[4], x2[4];
    for (int c = 0; c < 4; ++c) {
        int input_idx = n * (8 * H * W) + c * H * W + h * W + w;
        x1[c] = input[input_idx];
    }
    for (int c = 0; c < 4; ++c) {
        int input_idx = n * (8 * H * W) + (c +4) * H * W + h * W + w;
        x2[c] = input[input_idx];
    }

    float glu[4];
    for (int c = 0; c <4; ++c) {
        glu[c] = x1[c] * (1.0f / (1.0f + expf(-x2[c])));
    }

    float max_val = -INFINITY;
    for (int c=0; c<4; ++c) {
        max_val = fmaxf(max_val, glu[c]);
    }

    float sum_exp = 0.0f;
    for (int c=0; c<4; ++c) {
        sum_exp += expf(glu[c] - max_val);
    }

    float inv_sum = 1.0f / sum_exp;
    for (int c=0; c<4; ++c) {
        int output_idx = n * (4 * H * W) + c * H * W + h * W + w;
        output[output_idx] = expf(glu[c] - max_val) * inv_sum;
    }
}

