# CUDA kernel for fused min and sum reductions
source = """
#include <torch/extension.h>
#include <cuda.h>
#include <cuda_runtime.h>

__global__ void fused_min_sum_kernel(const float* input, float* output, int M, int N) {
    extern __shared__ float shared_sums[];

    int tid = blockIdx.x * blockDim.x + threadIdx.x;
    int thread_idx = threadIdx.x;

    float thread_sum = 0.0f;

    // Process multiple rows per thread
    for(int row = tid; row < M; row += gridDim.x * blockDim.x) {
        float min_val = INFINITY;
        for(int col = 0; col < N; ++col) {
            float val = input[row * N + col];
            if(val < min_val) min_val = val;
        }
        thread_sum += min_val;
    }

    shared_sums[thread_idx] = thread_sum;
    __syncthreads();

    // Block-level sum reduction
    for(int stride = blockDim.x/2; stride > 0; stride >>=1) {
        if(thread_idx < stride) {
            shared_sums[thread_idx] += shared_sums[thread_idx + stride];
        }
        __syncthreads();
    }

    // Atomic add to global output
    if(thread_idx == 0) {
        atomicAdd(output, shared_sums[0]);
    }
}

