import torch
import torch.nn as nn
from torch.utils.cpp_extension import load_inline

# Custom CUDA kernel for fused LayerNorm and Sigmoid
source = """
#include <torch/extension.h>
#include <cuda.h>
#include <cuda_runtime.h>

#define WARP_SIZE 32

__global__ void layer_norm_sigmoid_kernel(const float* input, const float* gamma, const float* beta, float* output, int num_features, float eps) {
    extern __shared__ float s_data[];

    int batch_idx = blockIdx.x;
    int tid = threadIdx.x;

    float x = input[batch_idx * num_features + tid];

    // Compute thread-local sum and sum of squares
    float sum = x;
    float sum_sq = x * x;

    // Warp-level reduction for sum and sum_sq
    for (int offset = WARP_SIZE/2; offset > 0; offset /= 2) {
        sum += __shfl_down_sync(0xffffffff, sum, offset);
        sum_sq += __shfl_down_sync(0xffffffff, sum_sq, offset);
    }

    // Store per-warp results in shared memory
    if (tid % WARP_SIZE == 0) {
        int warp_id = tid / WARP_SIZE;
        s_data[warp_id] = sum;
        s_data[warp_id + (blockDim.x/WARP_SIZE)] = sum_sq;
    }

    __syncthreads();

    // Compute global statistics in thread 0
    if (tid == 0) {
        int num_warps = blockDim.x / WARP_SIZE;
        float total_sum = 0.f;
        float total_sum_sq = 0.f;

        for (int i = 0; i < num_warps; ++i) {
            total_sum += s_data[i];
            total_sum_sq += s_data[i + num_warps];
        }

        float mean = total_sum / num_features;
        float variance = (total_sum_sq / num_features) - (mean * mean);
        float inv_std = rsqrtf(variance + eps);

        s_data[0] = mean;
        s_data[1] = inv_std;
    }

    __syncthreads();

    // Normalize and apply parameters
    float normalized = (x - s_data[0]) * s_data[1];
    float scaled = normalized * gamma[tid] + beta[tid];

    // Apply sigmoid
    output[batch_idx * num_features + tid] = 1.f / (1.f + expf(-scaled));
}

torch::Tensor layer_norm_sigmoid_cuda(torch::Tensor input, torch::Tensor gamma, torch::Tensor beta, float eps) {
    TORCH_CHECK(input.dim() == 2, "Input must be 2D [batch, features]");
    int batch_size = input.size(0);
    int num_features = input.size(1);

    auto output = torch::empty_like(input);

    dim3 grid(batch_size);
    dim3 block(num_features);

    // Shared memory: 2*num_warps for sums + 2 for mean/inv_std
    int num_warps = block.x / WARP_SIZE;
    size_t shared_size = (2 * num_warps + 2) * sizeof(float);

    layer_norm_sigmoid_kernel<<<grid, block, shared_size>>>(
        input.const_data_ptr<float>(),
        gamma.const_data_ptr<float>(),
        beta.const_data_ptr<float>(),
        output.data_ptr<float>(),
        num_features,
        eps
    );

    return output;
}
"""

