source = """
#include <torch/extension.h>

__global__ void interpolate_kernel(const float* input, float* output, float scale_factor,
                                   int input_H, int input_W,
                                   int output_H, int output_W,
                                   int input_stride_batch, int input_stride_channel, int input_stride_H, int input_stride_W,
                                   int output_stride_batch, int output_stride_channel, int output_stride_H, int output_stride_W) {
    int batch = blockIdx.z;
    int channel = blockIdx.y;
    int output_h = blockIdx.x;
    int output_w = threadIdx.x;

    if (output_w >= output_W) return;

    float input_h_f = (float)output_h / scale_factor;
    int input_h = min(static_cast<int>(input_h_f), input_H - 1);

    float input_w_f = (float)output_w / scale_factor;
    int input_w = min(static_cast<int>(input_w_f), input_W - 1);

    const float* input_ptr = input + batch * input_stride_batch + channel * input_stride_channel + input_h * input_stride_H + input_w * input_stride_W;
    float* output_ptr = output + batch * output_stride_batch + channel * output_stride_channel + output_h * output_stride_H + output_w * output_stride_W;

    *output_ptr = *input_ptr;
}

torch::Tensor interpolate_cuda(torch::Tensor input, float scale_factor) {
    int batch_size = input.size(0);
    int channels = input.size(1);
    int input_H = input.size(2);
    int input_W = input.size(3);
    int output_H = static_cast<int>(input_H * scale_factor);
    int output_W = static_cast<int>(input_W * scale_factor);

    torch::Tensor output = torch::empty({batch_size, channels, output_H, output_W}, input.options());

    dim3 block(output_W);
    dim3 grid(output_H, channels, batch_size);

    interpolate_kernel<<<grid, block>>>(
        input.data_ptr<float>(),
        output.data_ptr<float>(),
        scale_factor,
        input_H, input_W,
        output_H, output_W,
        input.stride(0), input.stride(1), input.stride(2), input.stride(3),
        output.stride(0), output.stride(1), output.stride(2), output.stride(3)
    );

    return output;
}

__global__ void topk_kernel(const float* input, float* output, int k, int W,
                            int input_stride_batch, int input_stride_channel, int input_stride_H, int input_stride_W,
                            int output_stride_batch, int output_stride_channel, int output_stride_H, int output_stride_k) {
    int batch = blockIdx.z;
    int channel = blockIdx.y;
    int H = blockIdx.x;
    int tid = threadIdx.x;

    extern __shared__ float shared[];

    if (tid < W) {
        const float* input_ptr = input + batch * input_stride_batch + channel * input_stride_channel + H * input_stride_H + tid * input_stride_W;
        shared[tid] = *input_ptr;
    } else {
        shared[tid] = -INFINITY;
    }

    __syncthreads();

    for (int len = 2; len <= W; len <<= 1) {
        for (int inc = len >> 1; inc > 0; inc >>= 1) {
            for (int i = tid; i < W; i += blockDim.x) {
                int j = i ^ inc;
                if (j > i) {
                    if ((i & len) == 0) {
                        if (shared[i] < shared[j]) {
                            float temp = shared[i];
                            shared[i] = shared[j];
                            shared[j] = temp;
                        }
                    } else {
                        if (shared[i] > shared[j]) {
                            float temp = shared[i];
                            shared[i] = shared[j];
                            shared[j] = temp;
                        }
                    }
                }
