# Custom CUDA kernel for fused product reduction and LeakyReLU
source = """
#include <torch/extension.h>

__global__ void fused_prod_leaky_relu_kernel(const float* input, float* output, int N, int C, int H, int W, float alpha) {
    int linear_idx = blockIdx.x * blockDim.x + threadIdx.x;
    if (linear_idx >= N * H * W) return;

    int elements_per_batch = H * W;
    int n = linear_idx / elements_per_batch;
    int hw = linear_idx % elements_per_batch;
    int h = hw / W;
    int w = hw % W;

    float product = 1.0f;
    for (int c = 0; c < C; ++c) {
        int input_idx = n * C * H * W + c * H * W + h * W + w;
        product *= input[input_idx];
    }

    output[linear_idx] = (product > 0.0f) ? product : product * alpha;
}

