#define CHECK_CUDNN(status) AT_CUDNN_CHECK(status, " at " __FILE__ ":", __LINE__)

struct cudnn_tensor_descriptor_deleter_t {
    void operator()(cudnnTensorDescriptor_t desc) { CHECK_CUDNN(cudnnDestroyTensorDescriptor(desc)); }
};
