unique_cudnn_convolution_descriptor_t make_unique_convolution_descriptor(const std::vector<int> &stride,
                                                                         const std::vector<int> &padding,
                                                                         const std::vector<int> &dilation) {
    cudnnConvolutionDescriptor_t desc;
    CHECK_CUDNN(cudnnCreateConvolutionDescriptor(&desc));
    CHECK_CUDNN(cudnnSetConvolutionNdDescriptor(desc, stride.size(), padding.data(), stride.data(), dilation.data(),
                                                CUDNN_CROSS_CORRELATION, CUDNN_DATA_FLOAT));
    return unique_cudnn_convolution_descriptor_t(desc);
}

torch::Tensor conv_transpose_cuda(torch::Tensor input, torch::Tensor weight, std::optional<torch::Tensor> bias,
                                  const std::vector<int> &stride, const std::vector<int> &padding,
                                  const std::vector<int> &output_padding, const std::vector<int> &dilation) {
    if (input.ndimension() == 3) {
        // Handle 1D by unsqueezing to 2D
        input = input.unsqueeze(-1);
        weight = weight.unsqueeze(-1);
        std::vector<int> new_stride{stride[0], 1};
        std::vector<int> new_padding{padding[0], 0};
        std::vector<int> new_output_padding{output_padding[0], 0};
        std::vector<int> new_dilation{dilation[0], 1};
        auto output = conv_transpose_cuda(input, weight, bias, new_stride, new_padding, new_output_padding, new_dilation);
        return output.squeeze(-1);
