__global__ void add_bias_kernel(float *x, const float *bias, int out_channels, int L, int total_elements) {
    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    if (idx < total_elements) {
        int c = (idx / L) % out_channels;
        x[idx] += bias[c];
    }
