    const int block_size = 256;
    int num_blocks = (total_elements + block_size - 1) / block_size;
    add_bias_kernel<<<num_blocks, block_size>>>(output.data_ptr<float>(), bias.data_ptr<float>(), out_channels, L, total_elements);
    return output;
}

__global__ void xor_kernel(const float *x, const int64_t *y, float *output, int total_elements) {
    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    if (idx < total_elements) {
        int32_t x_int = static_cast<int32_t>(x[idx]);
        int32_t y_int = static_cast<int32_t>(y[idx]);
        output[idx] = static_cast<float>(x_int ^ y_int);
    }
}

