import torch
import torch.nn as nn
from torch.utils.cpp_extension import load_inline

# Custom CUDA kernel for fused expm1 + max reduction + bias addition
source = """
#include <torch/extension.h>
#define WARP_SIZE 32

__device__ __forceinline__ float warp_reduce_max(float val) {
    for (int mask=16; mask>0; mask /=2)
        val = max(val, __shfl_xor_sync(0xffffffff, val, mask));
    return val;
}

__device__ __forceinline__ float block_reduce_max(float val) {
    __shared__ float shared[32]; 
    int lane = threadIdx.x % WARP_SIZE;
    int wid = threadIdx.x / WARP_SIZE;

    val = warp_reduce_max(val);

    if (lane == 0) shared[wid] = val;
    __syncthreads();

    val = (threadIdx.x < blockDim.x / WARP_SIZE) ? shared[lane] : -INFINITY;
    val = warp_reduce_max(val);
    return val;
}

__global__ void fused_kernel(const float* input, float* output, const float* bias, int N) {
    int batch_idx = blockIdx.x;
    int tid = threadIdx.x;

    const float* row = input + batch_idx * N;
    float local_max = -INFINITY;

    if (tid < N) {
        float val = expm1f(row[tid]);
        local_max = val;
    }

    float max_val = block_reduce_max(local_max);

    if (threadIdx.x == 0) {
        output[batch_idx] = max_val + bias[0];
    }
}

torch::Tensor fused_forward_cuda(torch::Tensor input, torch::Tensor bias) {
    int B = input.size(0);
    int N = input.size(1);
    auto output = torch::empty({B, 1}, input.options());

    dim3 grid(B), block(N);
    fused_kernel<<<grid, block>>>(input.data_ptr<float>(),
                                  output.data_ptr<float>(),
                                  bias.data_ptr<float>(),
                                  N);
    return output;
}
