source = """
#include <torch/extension.h>

__global__ void min_softmax_kernel(const float* input, const float* tensor1, float* output, 
                                   int batch_size, int dim1, int dim2) {
    const int idx = blockIdx.x * blockDim.x + threadIdx.x;
    if (idx >= batch_size * dim2) return;

    const int batch = idx / dim2;
    const int j = idx % dim2;
    float max_val = -INFINITY;
    float vals[10]; // dim1=10 from get_init_inputs()

    // 1. Compute element-wise minimum and find max
    for(int i=0; i<dim1; ++i) {
        const float x_val = input[batch*dim1*dim2 + i*dim2 + j];
        const float t_val = tensor1[i*dim2 + j];
        vals[i] = fminf(x_val, t_val);
        max_val = fmaxf(max_val, vals[i]);
    }

    // 2. Compute exp sum for softmax
    float sum_exp = 0.0f;
    for(int i=0; i<dim1; ++i) {
        sum_exp += expf(vals[i] - max_val);
    }
    const float inv_sum = 1.0f / sum_exp;

    // 3. Write normalized values
    for(int i=0; i<dim1; ++i) {
        output[batch*dim1*dim2 + i*dim2 + j] = expf(vals[i] - max_val) * inv_sum;
    }
}

