import torch
import torch.nn as nn
from torch.utils.cpp_extension import load_inline

# CUDA kernel for clamp and all reduction
source = """
#include <torch/extension.h>

__global__ void clamp_and_all_kernel(const float* input, float min_val, float max_val, bool* output, int M, int N) {
    int j = blockIdx.x; // Column index
    int i = threadIdx.x; // Thread index within block

    if (j >= N) return;

    bool all_non_zero = true;

    // Process rows in strided manner
    for (int row = i; row < M; row += blockDim.x) {
        float val = input[row * N + j];
        val = fmaxf(fminf(val, max_val), min_val);
        all_non_zero &= (val != 0.0f);
    }

    // Block-wide AND reduction using atomicAnd
    __shared__ int block_all;
    if (threadIdx.x == 0) block_all = 1;
    __syncthreads();

    if (!all_non_zero) atomicAnd(&block_all, 0);
    __syncthreads();

    if (threadIdx.x == 0) output[j] = (block_all != 0);
}

torch::Tensor clamp_and_all_cuda(torch::Tensor input, float min_val, float max_val) {
    input = input.contiguous();
    auto input_2d = input.view({input.size(0), -1});
    int M = input_2d.size(0);
    int N = input_2d.size(1);
    auto output = torch::empty({N}, input.options().dtype(torch::kBool));

    dim3 grid(N);
    int block_size = 256;
    dim3 block(block_size);

    clamp_and_all_kernel<<<grid, block>>>(
        input_2d.data_ptr<float>(),
        min_val,
        max_val,
        output.data_ptr<bool>(),
        M,
        N
    );

    auto output_shape = input.sizes().vec();
    output_shape.erase(output_shape.begin());
    return output.view(output_shape);
}
