import torch
import torch.nn as nn
from torch.utils.cpp_extension import load_inline

# CUDA kernel for fused einsum (identity) and group normalization
source = """
#include <torch/extension.h>
#include <cuda_fp16.h>
#include <cuda.h>
#include <cuda_runtime.h>

#define WARP_SIZE 32

__device__ __forceinline__ float warp_reduce_sum(float val) {
    for (int mask = 16; mask > 0; mask >>= 1)
        val += __shfl_xor_sync(0xffffffff, val, mask, 32);
    return val;
}

__global__ void group_norm_kernel(
    const float* input, float* output,
    const float* weight, const float* bias,
    int B, int C, int H, int W,
    int groups, float eps
) {
    const int G = groups;
    const int Gc = C / G;
    const int HW = H * W;
    const int spatial_size = Gc * HW;

    // Batch and group index
    int b = blockIdx.x / G;
    int g = blockIdx.x % G;

    // Shared memory for partial sums
    __shared__ float s_mean, s_var;

    float sum = 0.0f;
    float sum_sq = 0.0f;

    // Each thread handles multiple elements
    for (int idx = threadIdx.x; idx < spatial_size; idx += blockDim.x) {
        int c = g * Gc + idx / HW;
        int hw = idx % HW;
        float val = input[((b * C + c) * H + hw / W) * W + hw % W];
        sum += val;
        sum_sq += val * val;
    }

    // Warp-level reduction
    sum = warp_reduce_sum(sum);
    sum_sq = warp_reduce_sum(sum_sq);

    // First thread in warp writes to shared memory
    if (threadIdx.x % WARP_SIZE == 0) {
        atomicAdd(&s_mean, sum);
        atomicAdd(&s_var, sum_sq);
    }

    __syncthreads();

    if (threadIdx.x == 0) {
        float mean = s_mean / spatial_size;
        float var = (s_var / spatial_size) - (mean * mean);
        s_mean = mean;
        s_var = var + eps;
    }

    __syncthreads();

    float mean = s_mean;
    float inv_std = rsqrtf(s_var);

    // Apply normalization
    for (int idx = threadIdx.x; idx < spatial_size; idx += blockDim.x) {
        int c = g * Gc + idx / HW;
        int hw = idx % HW;
        int pos = ((b * C + c) * H + hw / W) * W + hw % W;

        float val = input[pos];
        float norm = (val - mean) * inv_std;
        output[pos] = norm * weight[c] + bias[c];
    }
}

torch::Tensor group_norm_cuda(
    torch::Tensor input,
    torch::Tensor weight,
    torch::Tensor bias,
    int groups,
    float eps
) {
    auto output = torch::empty_like(input);
    int B = input.size(0);
    int C = input.size(1);
    int H = input.size(2);
    int W = input.size(3);

    dim3 grid(B * groups);
    dim3 block(256);

    group_norm_kernel<<<grid, block>>>(
        input.const_data_ptr<float>(),
        output.mutable_data_ptr<float>(),
        weight.const_data_ptr<float>(),
        bias.const_data_ptr<float>(),
        B, C, H, W, groups, eps
    );

    return output;
}
