import torch
import torch.nn as nn
from torch.utils.cpp_extension import load_inline

# Define CUDA kernel for fused padding + erf operation
source = """
#include <torch/extension.h>
#include <cmath>

__global__ void pad_erf_kernel(const float* input, float* output,
                               int batch_size, int in_features,
                               int pad_left, int pad_right,
                               int pad_top, int pad_bottom,
                               float scale, float offset,
                               int out_batch, int out_features) {
    // 2D grid layout for output tensor
    int i = blockIdx.x * blockDim.x + threadIdx.x;
    int j = blockIdx.y * blockDim.y + threadIdx.y;

    if (i >= out_batch || j >= out_features) return;

    bool in_pad_top = i < pad_top;
    bool in_pad_bottom = i >= (pad_top + batch_size);
    bool in_pad_left = j < pad_left;
    bool in_pad_right = j >= (pad_left + in_features);

    float val = 0.0f;
    if (!(in_pad_top || in_pad_bottom || in_pad_left || in_pad_right)) {
        int orig_i = i - pad_top;
        int orig_j = j - pad_left;
        val = input[orig_i * in_features + orig_j];
    }

    output[i * out_features + j] = erff(val * scale + offset);
}

torch::Tensor pad_erf_cuda(torch::Tensor input, std::vector<int64_t> padding_size,
                          float scale, float offset) {
    TORCH_CHECK(padding_size.size() == 4, "Padding size must be 4 elements");
    int pad_left = padding_size[0], pad_right = padding_size[1];
    int pad_top = padding_size[2], pad_bottom = padding_size[3];

    int batch_size = input.size(0);
    int in_features = input.size(1);
    int out_batch = batch_size + pad_top + pad_bottom;
