#include <torch/extension.h>

__global__ void sort_last_dim_kernel(float* input, int B, int C, int H, int W) {
    int b = blockIdx.x;
    int c = blockIdx.y;
    int h = blockIdx.z;
    int tid = threadIdx.x;

    if (tid >= W) return;

    int index = b * C * H * W + c * H * W + h * W + tid;

    __shared__ float s_data[128];
    s_data[tid] = input[index];
    __syncthreads();

    // Bitonic sort implementation
    for (int k = 2; k <= W; k *= 2) {
        for (int j = k / 2; j > 0; j /= 2) {
            int ixj = tid ^ j;
            if (ixj > tid) {
                if ((tid & k) == 0) {
                    if (s_data[tid] > s_data[ixj]) {
                        float temp = s_data[tid];
                        s_data[tid] = s_data[ixj];
                        s_data[ixj] = temp;
                    }
                } else {
                    if (s_data[tid] < s_data[ixj]) {
                        float temp = s_data[tid];
                        s_data[tid] = s_data[ixj];
                        s_data[ixj] = temp;
                    }
                }
            }
            __syncthreads();
        }
    }

    input[index] = s_data[tid];
}

__global__ void unfold_kernel(const float* input, float* output,
                              int B, int C, int H, int W,
                              int K, int S, int P,
                              int OH, int OW, int OL) {
    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    if (idx >= B * C * K * K * OL) return;

    int elements_per_batch = C * K * K * OL;
    int b = idx / elements_per_batch;
    int remainder = idx % elements_per_batch;
    int k = remainder / OL;
    int l = remainder % OL;

    int c = k / (K * K);
    int kh = (k % (K * K)) / K;
    int kw = (k % (K * K)) % K;

    int i = l / OW;
    int j = l % OW;

    int start_h = i * S - P;
    int start_w = j * S - P;

    int input_h = start_h + kh;
    int input_w = start_w + kw;

    float val = 0.0f;
    if (input_h >= 0 && input_h < H && input_w >= 0 && input_w < W) {
        int input_idx = b * C * H * W + c * H * W + input_h * W + input_w;
        val = input[input_idx];
    }

    output[idx] = val;
}

torch::Tensor sort_last_dim_cuda(torch::Tensor input) {
    int B = input.size(0);
    int C = input.size(1);
    int H = input.size(2);
    int W = input.size(3);

    dim3 grid(B, C, H);
    dim3 block(W);
    sort_last_dim_kernel<<<grid, block>>>(input.data_ptr<float>(), B, C, H, W);
    return input;
}

torch::Tensor unfold_cuda(torch::Tensor input, int kernel_size, int stride, int padding) {
    int B = input.size(0);
    int C = input.size(1);
    int H = input.size(2);
    int W = input.size(3);

    int OH = (H + 2*padding - kernel_size) / stride + 1;
    int OW = (W + 2*padding - kernel_size) / stride + 1;
    int OL = OH * OW;

    auto options = torch::TensorOptions().dtype(input.dtype()).device(input.device());
    torch::Tensor output = torch::zeros({B, C * kernel_size * kernel_size, OL}, options);

    int total_elements = B * C * kernel_size * kernel_size * OL;
    int block_size = 256;
    int grid_size = (total_elements + block_size - 1) / block_size;

    unfold_kernel<<<grid_size, block_size>>>(
        input.const_data_ptr<float>(),
        output.data_ptr<float>(),
        B, C, H, W,
        kernel_size, stride, padding,
        OH, OW, OL
    );

    return output;
}
