    int row = blockIdx.x;
    int tid = threadIdx.x;

    if (row >= batch_size) return;

    // Compute log_softmax for input1[row]
    float max1 = -INFINITY;
    for (int i = tid; i < feature_size; i += blockDim.x) {
        float val = input1[row * feature_size + i];
        max1 = fmaxf(max1, val);
    }
    max1 = block_reduce_max(max1);

    float sum_exp1 = 0.0f;
    for (int i = tid; i < feature_size; i += blockDim.x) {
        sum_exp1 += expf(input1[row * feature_size + i] - max1);
    }
    sum_exp1 = block_reduce_sum(sum_exp1);
    float log_sum_exp1 = max1 + logf(sum_exp1);

    // Compute log_softmax for input2[row]
    float max2 = -INFINITY;
    for (int i = tid; i < feature_size; i += blockDim.x) {
        float val = input2[row * feature_size + i];
        max2 = fmaxf(max2, val);
    }
    max2 = block_reduce_max(max2);

    float sum_exp2 = 0.0f;
    for (int i = tid; i < feature_size; i += blockDim.x) {
        sum_exp2 += expf(input2[row * feature_size + i] - max2);
    }
    sum_exp2 = block_reduce_sum(sum_exp2);
    float log_sum_exp2 = max2 + logf(sum_exp2);

    // Compute KL loss elements
    for (int i = tid; i < feature_size; i += blockDim.x) {
        float log_softmax1 = input1[row * feature_size + i] - log_sum_exp1;
        float log_softmax2 = input2[row * feature_size + i] - log_sum_exp2;
