#include <ATen/cuda/CUDAContext.h>
#include <c10/cuda/CUDACachingAllocator.h>
#include <torch/extension.h>

__global__ void sigmoid_max_kernel(const float* input, float* output, int size) {
    const int idx = blockIdx.x * blockDim.x + threadIdx.x;
    if (idx < size) {
        float val = input[idx];
        float sig = 1.0f / (1.0f + expf(-val));
        output[idx] = fmaxf(sig, 0.0f);
    }
}

torch::Tensor sigmoid_max_cuda(torch::Tensor input) {
    auto output = torch::empty_like(input);
    int64_t size = input.numel();
    const int block_size = 256;
    int num_blocks = (size + block_size - 1) / block_size;
    sigmoid_max_kernel<<<num_blocks, block_size>>>(input.data_ptr<float>(), output.data_ptr<float>(), size);
    return output;
}

torch::Tensor linear_cuda(torch::Tensor x, torch::Tensor weight, torch::Tensor bias) {
    int M = x.size(0);
    int K = x.size(1);
    int N = weight.size(0);

    auto output = torch::empty({M, N}, x.options());

    const float *A = weight.data_ptr<float>();
    const float *B = x.data_ptr<float>();
    const float *bias_ptr = bias.data_ptr<float>();
    float *C = output.data_ptr<float>();

    const float alpha = 1.f;
    const float beta = 0.f;

    auto handle = at::cuda::getCurrentCUDABlasLtHandle();

    cublasLtMatmulDesc_t matmul_desc;
    cublasLtMatmulDescCreate(&matmul_desc, CUBLAS_COMPUTE_32F, CUDA_R_32F);

    cublasOperation_t trans_A = CUBLAS_OP_T;
    cublasLtMatmulDescSetAttribute(matmul_desc, CUBLASLT_MATMUL_DESC_TRANSA, &trans_A, sizeof(trans_A));
    cublasOperation_t trans_B = CUBLAS_OP_N;
    cublasLtMatmulDescSetAttribute(matmul_desc, CUBLASLT_MATMUL_DESC_TRANSB, &trans_B, sizeof(trans_B));

    auto epilogue = CUBLASLT_EPILOGUE_BIAS;
