__global__ void count_nonzero_kernel(const float* input, int* count, int num_elements) {
    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    if (idx < num_elements) {
        if (input[idx] != 0.0f) {
            atomicAdd(count, 1);
        }
    }
}

__global__ void fill_indices_kernel(const float* input, int64_t* indices, const int64_t* sizes, const int64_t* strides, int ndim, int num_elements, int* count) {
    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    if (idx < num_elements) {
        if (input[idx] != 0.0f) {
            int pos = atomicAdd(count, 1);
            int64_t offset = idx;
            for (int d = 0; d < ndim; ++d) {
                indices[pos * ndim + d] = (offset / strides[d]) % sizes[d];
                offset %= strides[d];
            }
        }
    }
}

__global__ void logical_or_kernel(const int64_t* first, const int64_t* last, bool* out, int ndim) {
    int idx = threadIdx.x;
    if (idx < ndim) {
        out[idx] = (first[idx] != 0) || (last[idx] != 0);
    }
}

__global__ void mean_kernel(const float* input, float* output, int64_t reduction_size, int64_t reduction_stride, int64_t output_numel) {
    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    if (idx < output_numel) {
        float sum = 0.0f;
        for (int64_t k = 0; k < reduction_size; ++k) {
            sum += input[idx + k * reduction_stride];
        }
        output[idx] = sum / reduction_size;
    }
}

