    cudaDeviceSynchronize();

    int count = count_tensor.item().toInt();
    if (count == 0) {
        return torch::empty({0, input.dim()}, input.options().dtype(torch::kLong));
    }

    auto indices = torch::empty({count, input.dim()}, input.options().dtype(torch::kLong));
