# Define the fused CUDA kernel for rsqrt and any reduction
source = """
#include <torch/extension.h>

__global__ void fused_rsqrt_any_kernel(const float* input, bool* output, int num_slices, int last_dim_size) {
    const int slice_idx = blockIdx.x;
    if (slice_idx >= num_slices) return;

    const float* slice_input = input + slice_idx * last_dim_size;
    bool* slice_output = output + slice_idx;

    bool thread_any = false;

    for (int i = threadIdx.x; i < last_dim_size; i += blockDim.x) {
        float x = slice_input[i];
        float val = rsqrtf(x);
        if (val != 0.0f) {
            thread_any = true;
        }
    }

    // Warp-level reduction
    thread_any = __any_sync(0xFFFFFFFF, thread_any);

    // Block-level reduction using shared memory
    __shared__ bool shared_any[32];
    int warp_id = threadIdx.x / 32;
    int lane_id = threadIdx.x % 32;

    if (lane_id == 0) {
        shared_any[warp_id] = thread_any;
    }
    __syncthreads();

    if (warp_id == 0) {
        bool val = (lane_id < (blockDim.x + 31) / 32) ? shared_any[lane_id] : false;
        val = __any_sync(0xFFFFFFFF, val);
        if (lane_id == 0) {
            *slice_output = val;
        }
    }
}

torch::Tensor fused_rsqrt_any_cuda(torch::Tensor input) {
    auto sizes = input.sizes().vec();
    int last_dim_size = sizes.back();
    sizes.pop_back();
    int num_slices = 1;
    for (auto s : sizes) {
        num_slices *= s;
    }

    auto output = torch::empty(sizes, input.options().dtype(torch::kBool));

    const int block_size = 256;
    dim3 grid(num_slices);
    dim3 block(block_size);

    fused_rsqrt_any_kernel<<<grid, block>>>(
        input.const_data_ptr<float>(),
        output.data_ptr<bool>(),
        num_slices,
        last_dim_size
    );

    return output;
}
