#include <torch/extension.h>
#include <math.h>

__global__ void fused_bn_hardtanh_kernel(
    const float* input,
    float* output,
    const float* gamma,
    const float* beta,
    const float* running_mean,
    const float* running_var,
    float eps,
    float min_val,
    float max_val,
    int num_elements,
    int C, int H, int W
) {
    const int idx = blockIdx.x * blockDim.x + threadIdx.x;
    if (idx >= num_elements) return;

    int channel_idx = (idx / (H * W)) % C;

    float x = input[idx];
    float mean = running_mean[channel_idx];
    float var = running_var[channel_idx];

    // BatchNorm calculation
    x = (x - mean) / sqrtf(var + eps);
    x = x * gamma[channel_idx] + beta[channel_idx];

    // Hardtanh activation
    x = fmaxf(min_val, fminf(x, max_val));

    output[idx] = x;
}

