# Custom CUDA kernel for fused isinf and all reduction
source = """
#include <torch/extension.h>

__global__ void fused_isinf_all_kernel(const float* input, bool* output, int batch_size, int C, int H, int W) {
    extern __shared__ bool sdata[];
    int batch_idx = blockIdx.x;
    if (batch_idx >= batch_size) return;

    int num_elements = C * H * W;
    int elements_per_thread = (num_elements + blockDim.x - 1) / blockDim.x;
    bool all_inf = true;

    for (int i = 0; i < elements_per_thread; ++i) {
        int element_idx = threadIdx.x + i * blockDim.x;
        if (element_idx >= num_elements) break;
        float val = input[batch_idx * num_elements + element_idx];
        if (!isinf(val)) all_inf = false;
    }

    sdata[threadIdx.x] = all_inf;
    __syncthreads();

    // Block-wide AND reduction
    for (int s = blockDim.x/2; s>0; s>>=1) {
        if (threadIdx.x < s) sdata[threadIdx.x] = sdata[threadIdx.x] && sdata[threadIdx.x+s];
        __syncthreads();
    }

    if (threadIdx.x == 0) output[batch_idx] = sdata[0];
}

torch::Tensor fused_isinf_all_cuda(torch::Tensor x) {
    TORCH_CHECK(x.dim() == 4, "Input must be 4D");
    auto sizes = x.sizes();
    int batch_size = sizes[0];
    int C = sizes[1];
    int H = sizes[2];
    int W = sizes[3];
    auto output = torch::empty({batch_size}, x.options().dtype(torch::kBool));

    if (x.numel() == 0) return output.fill_(true);

    const int block_size = 256;
    dim3 grid(batch_size);
    dim3 block(block_size);
    fused_isinf_all_kernel<<<grid, block, block_size*sizeof(bool)>>>(
        x.data_ptr<float>(),
        output.data_ptr<bool>(),
        batch_size,
        C,
        H,
        W
    );
    return output;
}
