source = """
#include <torch/extension.h>

__global__ void relu_concat_kernel(const float *input, float *output, int B, int C, int H, int W,
                                   int stride_B, int stride_C, int stride_H, int stride_W) {
    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    int total_elements = B * 2 * C * H * W;
    if (idx >= total_elements) return;

    // Calculate output indices
    int n = idx / (2 * C * H * W);
    int remaining = idx % (2 * C * H * W);
    int c = remaining / (H * W);
    remaining %= H * W;
    int h = remaining / W;
    int w = remaining % W;

    // Compute input channel and index
    int input_c = c % C;
    int input_idx = n * stride_B + input_c * stride_C + h * stride_H + w * stride_W;

    // Apply ReLU and write to output
    output[idx] = fmaxf(input[input_idx], 0.0f);
}

