# CUDA kernel for fused clamp-digamma-clamp operations
source = """
#include <torch/extension.h>
#include <cuda.h>
#include <cuda_runtime.h>
#include <cmath>

__global__ void clamp_digamma_clamp_kernel(const float* input, float* output, int size, float clamp_value, int dig_base) {
    const int idx = blockIdx.x * blockDim.x + threadIdx.x;
    if (idx >= size) return;

    float x = input[idx];

    // First clamp
    x = fminf(fmaxf(x, 0.0f), clamp_value);

    if (x == 0.0f) {
        x = -INFINITY;
    } else {
        if (x >= dig_base) {
            // Asymptotic expansion for x >= dig_base
            const float x_sq = x * x;
            const float x_quad = x_sq * x_sq;
            x = logf(x) - 1.0f/(2.0f*x) - 1.0f/(12.0f*x_sq) + 1.0f/(120.0f*x_quad);
        } else {
            // Recurrence relation for x < dig_base
            int n = static_cast<int>(ceilf(dig_base - x));
            const float shifted_x = x + n;
            const float shifted_sq = shifted_x * shifted_x;
            const float shifted_quad = shifted_sq * shifted_sq;
            float approx = logf(shifted_x) - 1.0f/(2.0f*shifted_x) - 1.0f/(12.0f*shifted_sq) + 1.0f/(120.0f*shifted_quad);

            float sum = 0.0f;
            for (int k = 0; k < n; ++k) {
                sum += 1.0f/(x + static_cast<float>(k));
            }
            x = approx - sum;
        }
    }

    // Second clamp and write output
    output[idx] = fminf(fmaxf(x, 0.0f), clamp_value);
}

torch::Tensor forward_cuda(torch::Tensor input, float clamp_value, int dig_base) {
    auto output = torch::empty_like(input);
    const int size = input.numel();
    const int block_size = 256;
    const int num_blocks = (size + block_size - 1) / block_size;

    clamp_digamma_clamp_kernel<<<num_blocks, block_size>>>(
        input.data_ptr<float>(),
        output.data_ptr<float>(),
        size,
        clamp_value,
        dig_base
    );

    return output;
}
