# CUDA kernel for fused linear + ReLU using cuBLASLt with epilogue
source = """
#include <ATen/cuda/CUDAContext.h>
#include <c10/cuda/CUDACachingAllocator.h>
#include <torch/extension.h>

#define CHECK_CUBLAS(status) TORCH_CHECK(status == CUBLAS_STATUS_SUCCESS, "cuBLAS error: ", status)

torch::Tensor fused_linear_relu_cuda(torch::Tensor x, torch::Tensor weight, std::optional<torch::Tensor> bias) {
    cublasLtHandle_t handle = at::cuda::getCurrentCUDABlasLtHandle();
    cublasLtMatmulDesc_t matmul_desc;
    cublasLtMatmulDescCreate(&matmul_desc, CUBLAS_COMPUTE_32F, CUDA_R_32F);

    // Set matrix transpositions
    cublasOperation_t transA = CUBLAS_OP_T, transB = CUBLAS_OP_N;
    CHECK_CUBLAS(cublasLtMatmulDescSetAttribute(matmul_desc, CUBLASLT_MATMUL_DESC_TRANSA, &transA, sizeof(transA)));
    CHECK_CUBLAS(cublasLtMatmulDescSetAttribute(matmul_desc, CUBLASLT_MATMUL_DESC_TRANSB, &transB, sizeof(transB)));

    // Configure epilogue (ReLU + optional bias)
    cublasLtEpilogue_t epilogue = bias ? CUBLASLT_EPILOGUE_RELU_BIAS : CUBLASLT_EPILOGUE_RELU;
    CHECK_CUBLAS(cublasLtMatmulDescSetAttribute(matmul_desc, CUBLASLT_MATMUL_DESC_EPILOGUE, &epilogue, sizeof(epilogue)));
    const float* bias_ptr = bias ? bias->data_ptr<float>() : nullptr;
    if (bias) {
        CHECK_CUBLAS(cublasLtMatmulDescSetAttribute(matmul_desc, CUBLASLT_MATMUL_DESC_BIAS_POINTER, &bias_ptr, sizeof(bias_ptr)));
    }

    // Create matrix layouts
    cublasLtMatrixLayout_t A_desc, B_desc, C_desc;
    CHECK_CUBLAS(cublasLtMatrixLayoutCreate(&A_desc, CUDA_R_32F, weight.size(1), weight.size(0), weight.stride(0)));
    CHECK_CUBLAS(cublasLtMatrixLayoutCreate(&B_desc, CUDA_R_32F, x.size(1), x.size(0), x.stride(0)));
    CHECK_CUBLAS(cublasLtMatrixLayoutCreate(&C_desc, CUDA_R_32F, weight.size(0), x.size(0), weight.size(0)));

    // Allocate output tensor
    auto output = torch::empty({x.size(0), weight.size(0)}, x.options());
    float alpha = 1.0f, beta = 0.0f;

    // Get workspace size and allocate
    size_t workspace_size = 1024 * 1024;
    auto workspace = c10::cuda::CUDACachingAllocator::get()->allocate(workspace_size);

    // Find optimal algorithm
    cublasLtMatmulPreference_t preference;
    CHECK_CUBLAS(cublasLtMatmulPreferenceCreate(&preference));
    CHECK_CUBLAS(cublasLtMatmulPreferenceSetAttribute(preference, CUBLASLT_MATMUL_PREF_MAX_WORKSPACE_BYTES, &workspace_size, sizeof(workspace_size)));

    cublasLtMatmulHeuristicResult_t heuristic_result = {};
    int returned_algo_count = 0;
    CHECK_CUBLAS(cublasLtMatmulAlgoGetHeuristic(
        handle, matmul_desc, A_desc, B_desc, C_desc, C_desc,
        preference, 1, &heuristic_result, &returned_algo_count
    ));
    TORCH_CHECK(returned_algo_count > 0, "No valid cuBLASLt algorithm found");

    // Execute matmul with fused epilogue
    CHECK_CUBLAS(cublasLtMatmul(
        handle, matmul_desc, &alpha,
        weight.data_ptr<float>(), A_desc,
        x.data_ptr<float>(), B_desc, 
        &beta,
        output.data_ptr<float>(), C_desc,
        output.data_ptr<float>(), C_desc,
        &heuristic_result.algo, workspace.get(), workspace_size, at::cuda::getCurrentCUDAStream()
    ));

    // Cleanup
    cublasLtMatmulPreferenceDestroy(preference);
    cublasLtMatrixLayoutDestroy(A_desc);
    cublasLtMatrixLayoutDestroy(B_desc);
    cublasLtMatrixLayoutDestroy(C_desc);
    cublasLtMatmulDescDestroy(matmul_desc);

    return output;
}
"""

