import torch
import torch.nn as nn
from torch.utils.cpp_extension import load_inline

# CUDA kernel for fused adaptive average pool + relu
source = """
#include <torch/extension.h>

__global__ void adaptive_avg_pool_relu_kernel(const float* input, float* output,
                                               int B, int C, int H, int W, int KH, int KW) {
    const int b = blockIdx.x;
    const int c = blockIdx.y;
    const int oh = threadIdx.x;
    const int ow = threadIdx.y;

    const int input_offset = b * C * H * W + c * H * W;
    const int output_idx = b * C * KH * KW + c * KH * KW + oh * KW + ow;

    const int h_start = (H / KH) * oh;
    const int h_end = (oh == KH - 1) ? H : (H / KH) * (oh + 1);
    const int w_start = (W / KW) * ow;
    const int w_end = (ow == KW - 1) ? W : (W / KW) * (ow + 1);

    float sum = 0.0f;
    int count = 0;
    for (int h = h_start; h < h_end; ++h) {
        for (int w = w_start; w < w_end; ++w) {
            sum += input[input_offset + h * W + w];
            count++;
        }
    }
    float avg = count > 0 ? sum / count : 0.0f;
    output[output_idx] = fmaxf(avg, 0.0f);
}

torch::Tensor adaptive_avg_pool_relu_cuda(torch::Tensor input, int KH, int KW) {
    int B = input.size(0);
    int C = input.size(1);
    auto output = torch::empty({B, C, KH, KW}, input.options());

    dim3 blocks(B, C);
    dim3 threads(KH, KW);
    adaptive_avg_pool_relu_kernel<<<blocks, threads>>>(
        input.const_data_ptr<float>(),
