#include <torch/extension.h>

__global__ void fused_sigmoid_conv1d_kernel(
    const float* input, const float* weight, const float* bias, float* output,
    int batch_size, int in_channels, int out_channels,
    int input_width, int kernel_size, int output_width
) {
    const int index = blockIdx.x * blockDim.x + threadIdx.x;
    if (index >= batch_size * out_channels * output_width) return;

    const int b = index / (out_channels * output_width);
    const int oc = (index % (out_channels * output_width)) / output_width;
    const int ow = index % output_width;

    float sum = 0.0f;
    for (int ic = 0; ic < in_channels; ++ic) {
        for (int k = 0; k < kernel_size; ++k) {
            const int input_pos = b * in_channels * input_width + ic * input_width + ow + k;
            const float x = input[input_pos];
            const float sig_x = 1.0f / (1.0f + expf(-x));
            sum += sig_x * weight[oc * in_channels * kernel_size + ic * kernel_size + k];
        }
    }
    sum += bias[oc];
    output[index] = sum;
}

