from torch.utils.cpp_extension import load_inline

# Custom CUDA kernel for Lp normalization
source = """
#include <torch/extension.h>

#define WARP_SIZE 32

__device__ __forceinline__ float warp_reduce_sum(float v) {
#pragma unroll
    for (int mask = 16; mask > 0; mask >>= 1) {
        v += __shfl_xor_sync(0xffffffff, v, mask);
    }
    return v;
}

__device__ __forceinline__ float block_reduce_sum(float v) {
    const int num_warps = blockDim.x / WARP_SIZE;
    v = warp_reduce_sum(v);
    __shared__ float shm[32];
    const int warp_id = threadIdx.x / WARP_SIZE;
    const int lane_id = threadIdx.x % WARP_SIZE;
    if (lane_id == 0) {
        shm[warp_id] = v;
    }
    __syncthreads();
    v = (lane_id < num_warps) ? shm[lane_id] : 0.0f;
    v = warp_reduce_sum(v);
    return v;
}

__global__ void normalize_kernel(const float* input, float* output, int D, float p, float eps) {
    int row = blockIdx.x;
    int tid = threadIdx.x;
    int stride = blockDim.x;

    // Compute sum of absolute values raised to p
    float sum = 0.0f;
    for (int i = tid; i < D; i += stride) {
        float val = input[row * D + i];
        sum += powf(fabsf(val), p);
    }

    // Block-wide sum reduction
    sum = block_reduce_sum(sum);

    // Compute normalization factor
    __shared__ float s_norm;
    if (tid == 0) {
        s_norm = powf(sum + eps, 1.0f / p);
    }
    __syncthreads();

    // Apply normalization
    for (int i = tid; i < D; i += stride) {
        output[row * D + i] = input[row * D + i] / s_norm;
    }
}

torch::Tensor normalize_cuda(torch::Tensor input, float p) {
    TORCH_CHECK(input.dim() == 2, "Input must be 2D");
    int N = input.size(0);
    int D = input.size(1);
    torch::Tensor output = torch::empty_like(input);
    float eps = 1e-12;

    int block_size = min(256, D);
    dim3 grid(N);
    normalize_kernel<<<grid, block_size>>>(
        input.data_ptr<float>(),
        output.mutable_data_ptr<float>(),
        D,
        p,
        eps
    );
    return output;
}
