import torch
import torch.nn as nn
from torch.utils.cpp_extension import load_inline

# CUDA kernel for fused logsumexp + stack operation
source = """
#include <torch/extension.h>
#include <cuda.h>
#include <cuda_runtime.h>

__global__ void logsumexp_stack_kernel(const float* input, float* output, int batch_size, int timesteps, int features) {
    const int idx = blockIdx.x * blockDim.x + threadIdx.x;
    if (idx >= batch_size * features) return;

    const int batch = idx / features;
    const int feature = idx % features;

    // Find max value across timesteps
    float max_val = -INFINITY;
    for (int t = 0; t < timesteps; ++t) {
        const float val = input[batch * timesteps * features + t * features + feature];
        max_val = fmaxf(max_val, val);
    }

    // Compute sum of exp(x - max)
    float sum_exp = 0.0f;
    for (int t = 0; t < timesteps; ++t) {
        const float val = input[batch * timesteps * features + t * features + feature];
        sum_exp += expf(val - max_val);
    }

    // Final logsumexp value
    const float logsumexp = logf(sum_exp) + max_val;

    // Write to both positions in output tensor
    const int base = batch * 2 * features;
    output[base + feature] = logsumexp;
