__global__ void logsumexp_stack_kernel(const float* input, float* output, int batch_size, int timesteps, int features) {
    const int idx = blockIdx.x * blockDim.x + threadIdx.x;
    if (idx >= batch_size * features) return;

    const int batch = idx / features;
    const int feature = idx % features;

    // Find max value across timesteps
