source = """
#include <torch/extension.h>
#include <cuda.h>
#include <cuda_runtime.h>

#define WARP_SIZE 32

__device__ __forceinline__ float warp_reduce_max(float v) {
#pragma unroll
    for (int mask = 16; mask > 0; mask /= 2) {
        v = fmaxf(v, __shfl_xor_sync(0xffffffff, v, mask));
    }
    return v;
}

__device__ __forceinline__ float block_reduce_max(float v) {
    const int num_warps = blockDim.x / WARP_SIZE;
    v = warp_reduce_max(v);
    __shared__ float shm[32];
    const int warp_id = threadIdx.x / WARP_SIZE;
    const int lane_id = threadIdx.x % WARP_SIZE;
    if (lane_id == 0) {
        shm[warp_id] = v;
    }
    __syncthreads();
    v = (lane_id < num_warps) ? shm[lane_id] : -INFINITY;
    v = warp_reduce_max(v);
    return v;
}

__device__ __forceinline__ float warp_reduce_sum(float v) {
#pragma unroll
    for (int mask = 16; mask > 0; mask /= 2) {
        v += __shfl_xor_sync(0xffffffff, v, mask);
    }
    return v;
}

__device__ __forceinline__ float block_reduce_sum(float v) {
    const int num_warps = blockDim.x / WARP_SIZE;
    v = warp_reduce_sum(v);
    __shared__ float shm[32];
    const int warp_id = threadIdx.x / WARP_SIZE;
    const int lane_id = threadIdx.x % WARP_SIZE;
    if (lane_id == 0) {
        shm[warp_id] = v;
    }
    __syncthreads();
    v = (lane_id < num_warps) ? shm[lane_id] : 0.0f;
    v = warp_reduce_sum(v);
    return v;
}

__global__ void fused_softmax_add_kernel(const float* input, const float* add_value, float* output, int N, int S) {
    const int tile_offset = (blockIdx.x - blockIdx.x % S) * N + blockIdx.x % S;
    const float* input_tile = input + tile_offset;
    float* output_tile = output + tile_offset;

    float max_val = -INFINITY;
    for (int i = threadIdx.x; i < N; i += blockDim.x) {
        max_val = fmaxf(max_val, input_tile[i * S]);
    }
    max_val = block_reduce_max(max_val);

    float sum = 0.0f;
    for (int i = threadIdx.x; i < N; i += blockDim.x) {
        sum += expf(input_tile[i * S] - max_val);
    }
    sum = block_reduce_sum(sum);
    const float inv_sum = 1.0f / sum;

    for (int i = threadIdx.x; i < N; i += blockDim.x) {
        output_tile[i * S] = expf(input_tile[i * S] - max_val) * inv_sum + add_value[i];
    }
}

