        // GELU with tanh approximation
        float gelu = x * 0.5f * (1.0f + tanhf(0.7978845608f * (x + 0.044715f * x * x * x)));
        // LeakyReLU
        output[idx] = (gelu > 0.0f) ? gelu : (negative_slope * gelu);
    }
}

