#include <torch/extension.h>
#include <math.h>

__global__ void adaptive_avg_pool_gelu_kernel(const float* input, float* output, int B, int C, int H_in, int W_in, int H_out, int W_out) {
    int index = blockIdx.x * blockDim.x + threadIdx.x;
    if (index >= B * C * H_out * W_out) return;

    int b = index / (C * H_out * W_out);
    int remainder = index % (C * H_out * W_out);
    int c = remainder / (H_out * W_out);
    remainder = remainder % (H_out * W_out);
    int i = remainder / W_out;
    int j = remainder % W_out;

    int start_h = (i * H_in) / H_out;
    int end_h = ((i + 1) * H_in + H_out - 1) / H_out;

    int start_w = (j * W_in) / W_out;
    int end_w = ((j + 1) * W_in + W_out - 1) / W_out;

    float sum = 0.0f;
    for (int h = start_h; h < end_h; ++h) {
        for (int w = start_w; w < end_w; ++w) {
            int input_idx = b * C * H_in * W_in + c * H_in * W_in + h * W_in + w;
            sum += input[input_idx];
        }
    }

    int area = (end_h - start_h) * (end_w - start_w);
    float avg = sum / area;

    const float sqrt_2_over_pi = 0.7978845608f;
    const float coeff = 0.044715f;
    float cubed = avg * avg * avg;
    float inner = sqrt_2_over_pi * (avg + coeff * cubed);
    float tanh_val = tanhf(inner);
    output[index] = 0.5f * avg * (1.0f + tanh_val);
}

