#include <cublas_v2.h>

__global__ void add_bias_softplus_kernel(float* gemm_output, const float* bias, float* output, int total_elements) {
    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    if (idx < total_elements) {
        float val = gemm_output[idx] + bias[idx];
        output[idx] = log(1.0f + expf(val));
    }
}

torch::Tensor baddbmm_softplus_cuda(torch::Tensor batch1, torch::Tensor batch2, torch::Tensor bias) {
    int B = batch1.size(0);
    int H = batch1.size(1);
    int I = batch1.size(2);
    TORCH_CHECK(batch2.size(0) == B && batch2.size(1) == I && batch2.size(2) == 1, "Invalid batch2 shape");

    auto gemm_output = torch::empty({B, H, 1}, batch1.options());
    cublasHandle_t handle;
    cublasCreate(&handle);

    float alpha = 1.0f, beta = 0.0f;
    cublasSgemmStridedBatched(handle,
                              CUBLAS_OP_T,
                              CUBLAS_OP_N,
                              H, 1, I,
                              &alpha,
                              batch1.data_ptr<float>(), I, H * I,
                              batch2.data_ptr<float>(), I, I * 1,
                              &beta,
                              gemm_output.data_ptr<float>(), H, H * 1,
                              B);
    cublasDestroy(handle);

    auto output = torch::empty_like(gemm_output);
    int total_elements = B * H;
    int block_size = 256;
    int grid_size = (total_elements + block_size - 1) / block_size;
    add_bias_softplus_kernel<<<grid_size, block_size>>>(
        gemm_output.data_ptr<float>(),
        bias.data_ptr<float>(),
        output.data_ptr<float>(),
        total_elements
    );
    return output;
}
