# CUDA kernel for fused padding and PReLU
source = """
#include <torch/extension.h>

__global__ void fused_pad_prelu_kernel(
    const float* input,
    const float* weight,
    float* output,
    int pad_left, int pad_right, int pad_top, int pad_bottom,
    int N, int C, int H_in, int W_in,
    int H_out, int W_out,
    int num_parameters) {

    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    int total_elements = N * C * H_out * W_out;

    for (; idx < total_elements; idx += blockDim.x * gridDim.x) {
        int n = idx / (C * H_out * W_out);
        int remainder = idx % (C * H_out * W_out);
        int c = remainder / (H_out * W_out);
        remainder = remainder % (H_out * W_out);
        int h_out = remainder / W_out;
        int w_out = remainder % W_out;

        bool in_pad = (h_out < pad_top) || (h_out >= (H_in + pad_top)) || 
                      (w_out < pad_left) || (w_out >= (W_in + pad_left));

        if (in_pad) {
            output[idx] = 0.0f;
        } else {
            int h_in = h_out - pad_top;
            int w_in = w_out - pad_left;
            int input_idx = n * (C * H_in * W_in) + c * (H_in * W_in) + h_in * W_in + w_in;
            float x = input[input_idx];
            float a = weight[(num_parameters > 1) ? c : 0];
            output[idx] = x > 0 ? x : a * x;
        }
    }
}

torch::Tensor fused_pad_prelu_cuda(torch::Tensor input, torch::Tensor weight, 
                                 int pad_left, int pad_right, int pad_top, int pad_bottom) {
    int N = input.size(0);
    int C = input.size(1);
    int H_in = input.size(2);
    int W_in = input.size(3);
    int H_out = H_in + pad_top + pad_bottom;
    int W_out = W_in + pad_left + pad_right;

    auto output = torch::empty({N, C, H_out, W_out}, input.options());
    int num_parameters = weight.numel();

    int total_elements = output.numel();
    const int block_size = 256;
    const int grid_size = (total_elements + block_size - 1) / block_size;

    fused_pad_prelu_kernel<<<grid_size, block_size>>>(
        input.const_data_ptr<float>(),
        weight.const_data_ptr<float>(),
        output.data_ptr<float>(),
        pad_left, pad_right, pad_top, pad_bottom,
        N, C, H_in, W_in, H_out, W_out,
