import torch
import torch.nn as nn
from torch.utils.cpp_extension import load_inline

# CUDA code for fused embedding lookup, mask, scaling, and Hardswish
source = """
#include <torch/extension.h>

__global__ void fused_embedding_mask_hardswish_kernel(
    const int64_t* input_mat,
    const int64_t* element_values,
    const float* embedding_weight,
    float* output,
    float scale,
    int batch_size,
    int seq_len,
    int emb_size,
    int num_elements) {

    int flat_idx = blockIdx.x;
    int i = flat_idx / seq_len;
    int j = flat_idx % seq_len;

    if (i >= batch_size || j >= seq_len) return;

    __shared__ int mask_val;

    if (threadIdx.x == 0) {
        int64_t current_idx = input_mat[i * seq_len + j];
        mask_val = 0;
        for (int e = 0; e < num_elements; ++e) {
            if (element_values[e] == current_idx) {
                mask_val = 1;
                break;
            }
        }
    }

    __syncthreads();

    int k = threadIdx.x;
    if (k >= emb_size) return;

    int64_t current_idx = input_mat[i * seq_len + j];
    float val = mask_val ? embedding_weight[current_idx * emb_size + k] * scale : 0.0f;

    if (mask_val) {
        val = val * __fdividef(fminf(fmaxf(val + 3.0f, 0.0f), 6.0f), 6.0f);
    }

    output[i * seq_len * emb_size + j * emb_size + k] = val;
}

torch::Tensor fused_forward_cuda(
    torch::Tensor input_mat,
    torch::Tensor element_values,
    torch::Tensor embedding_weight,
    float scale) {

    int batch_size = input_mat.size(0);
    int seq_len = input_mat.size(1);
    int emb_size = embedding_weight.size(1);
    int num_elements = element_values.size(0);

    auto output = torch::zeros({batch_size, seq_len, emb_size}, embedding_weight.options());

    int num_blocks = batch_size * seq_len;
    int threads_per_block = emb_size;

    fused_embedding_mask_hardswish_kernel<<<num_blocks, threads_per_block>>>(
        input_mat.data_ptr<int64_t>(),
        element_values.data_ptr<int64_t>(),
        embedding_weight.data_ptr<float>(),
        output.data_ptr<float>(),
        scale,
        batch_size,
        seq_len,
        emb_size,
        num_elements);

    return output;
}
