__global__ void fused_embedding_mask_hardswish_kernel(
    const int64_t* input_mat,
    const int64_t* element_values,
    const float* embedding_weight,
    float* output,
    float scale,
    int batch_size,
    int seq_len,
    int emb_size,
    int num_elements) {

