import torch
import torch.nn as nn
from torch.utils.cpp_extension import load_inline

# CUDA kernel for optimized conv1d with generated weights
source = """
#include <torch/extension.h>

__global__ void conv1d_kernel(
    const float* x, const float* bias, float* output,
    int batch_size, int in_channels, int out_channels, int kernel_size,
    int input_length, int output_length, int stride, int padding, int dilation
) {
    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    if (idx >= batch_size * out_channels * output_length) return;

    int b = idx / (out_channels * output_length);
    int remainder = idx % (out_channels * output_length);
    int o = remainder / output_length;
    int pos = remainder % output_length;

    float sum = 0.0f;

    for (int i = 0; i < in_channels; ++i) {
        for (int k = 0; k < kernel_size; ++k) {
            int input_pos = pos * stride + k * dilation - padding;
            if (input_pos >= 0 && input_pos < input_length) {
                int x_idx = b * (in_channels * input_length) + i * input_length + input_pos;
                float weight_val = o * in_channels * kernel_size + i * kernel_size + k;
                sum += x[x_idx] * weight_val;
            }
        }
    }

    output[idx] = sum + bias[o];
}

torch::Tensor conv1d_cuda(
    torch::Tensor x, torch::Tensor bias,
    int in_channels, int out_channels, int kernel_size,
    int stride, int padding, int dilation
) {
    x = x.contiguous();
    bias = bias.contiguous();

    int batch_size = x.size(0);
    int input_length = x.size(2);
    int output_length = ((input_length + 2*padding - dilation*(kernel_size-1)-1)/stride) + 1;

    auto output = torch::empty({batch_size, out_channels, output_length}, x.options());

    int num_elements = batch_size * out_channels * output_length;
    int block_size = 256;
    int grid_size = (num_elements + block_size - 1) / block_size;

    conv1d_kernel<<<grid_size, block_size>>>(
        x.data_ptr<float>(),
        bias.data_ptr<float>(),
        output.data_ptr<float>(),
        batch_size, in_channels, out_channels, kernel_size,
        input_length, output_length, stride, padding, dilation
    );

    return output;
}
