    int output_length = ((input_length + 2*padding - dilation*(kernel_size-1)-1)/stride) + 1;

    auto output = torch::empty({batch_size, out_channels, output_length}, x.options());

    int num_elements = batch_size * out_channels * output_length;
    int block_size = 256;
    int grid_size = (num_elements + block_size - 1) / block_size;

