# Custom fused CUDA kernel for log2 + bilinear interpolation
source = """
#include <torch/extension.h>
#include <cuda.h>
#include <cuda_runtime.h>
#include <math.h>

__global__ void log2_interpolate_kernel(const float* input, float* output,
                                        int batch_size, int channels,
                                        int in_height, int in_width,
                                        int out_height, int out_width,
                                        float scale_factor) {
    const int idx = blockIdx.x * blockDim.x + threadIdx.x;
    if (idx >= batch_size * channels * out_height * out_width) return;

    // Convert linear index to 4D coordinates
    const int n = idx / (channels * out_height * out_width);
    const int c = (idx / (out_height * out_width)) % channels;
    const int h = (idx / out_width) % out_height;
    const int w = idx % out_width;

    // Compute input coordinates with align_corners=False logic
    const float x = (h + 0.5f) / scale_factor - 0.5f;
    const float y = (w + 0.5f) / scale_factor - 0.5f;

    const int x0 = static_cast<int>(floorf(x));
    const int y0 = static_cast<int>(floorf(y));
    const int x1 = x0 + 1;
    const int y1 = y0 + 1;

    const float dx = x - x0;
    const float dy = y - y0;

    // Clamp coordinates to input spatial dimensions
    const int x0_clamped = max(0, min(x0, in_height - 1));
    const int x1_clamped = max(0, min(x1, in_height - 1));
    const int y0_clamped = max(0, min(y0, in_width - 1));
    const int y1_clamped = max(0, min(y1, in_width - 1));

    // Calculate weights and input indices
    const float w00 = (1 - dx) * (1 - dy);
    const float w01 = (1 - dx) * dy;
    const float w10 = dx * (1 - dy);
    const float w11 = dx * dy;

    const int in_idx00 = ((n * channels + c) * in_height + x0_clamped) * in_width + y0_clamped;
    const int in_idx01 = ((n * channels + c) * in_height + x0_clamped) * in_width + y1_clamped;
    const int in_idx10 = ((n * channels + c) * in_height + x1_clamped) * in_width + y0_clamped;
    const int in_idx11 = ((n * channels + c) * in_height + x1_clamped) * in_width + y1_clamped;

    // Compute fused log2 and interpolation
    output[idx] = w00 * log2f(input[in_idx00]) +
                  w01 * log2f(input[in_idx01]) +
                  w10 * log2f(input[in_idx10]) +
                  w11 * log2f(input[in_idx11]);
}

torch::Tensor fused_log2_interpolate_cuda(torch::Tensor input, float scale_factor, std::string mode) {
    TORCH_CHECK(mode == "bilinear", "Only bilinear mode supported");
    auto input_contig = input.contiguous();
    auto input_sizes = input_contig.sizes();

    const int batch_size = input_sizes[0];
    const int channels = input_sizes[1];
    const int in_height = input_sizes[2];
    const int in_width = input_sizes[3];
    const int out_height = static_cast<int>(in_height * scale_factor);
    const int out_width = static_cast<int>(in_width * scale_factor);

    auto output = torch::empty({batch_size, channels, out_height, out_width}, input_contig.options());

    const int total = batch_size * channels * out_height * out_width;
    const int threads = 256;
    const int blocks = (total + threads - 1) / threads;

    log2_interpolate_kernel<<<blocks, threads>>>(
        input_contig.data_ptr<float>(),
        output.data_ptr<float>(),
        batch_size,
        channels,
        in_height,
        in_width,
        out_height,
        out_width,
        scale_factor
    );

    return output;
}
