# Custom CUDA kernel for fused embedding lookup, min reduction, and clamp
source = """
#include <torch/extension.h>

__global__ void embedding_min_clamp_kernel(
    const int64_t* x, 
    const float* embedding_weight, 
    float min_value, 
    float* output, 
    int x_size, 
    int embedding_dim
) {
    const int idx = blockIdx.x;
    if (idx >= x_size) return;

    const int64_t embedding_idx = x[idx];
    const float* vec = embedding_weight + embedding_idx * embedding_dim;

    float thread_min = INFINITY;
    for (int i = threadIdx.x; i < embedding_dim; i += blockDim.x) {
        thread_min = fminf(thread_min, vec[i]);
    }

    // Warp-level min reduction
    for (int offset = 16; offset > 0; offset >>= 1) {
        thread_min = fminf(thread_min, __shfl_down_sync(0xffffffff, thread_min, offset));
    }

    if (threadIdx.x == 0) {
        output[idx] = fmaxf(thread_min, min_value);
    }
}

