#include <torch/extension.h>

#define WARP_SIZE 32

__device__ __forceinline__ float warp_reduce_max(float v) {
#pragma unroll
    for (int mask = 16; mask > 0; mask /= 2) {
        v = fmaxf(v, __shfl_xor_sync(0xffffffff, v, mask));
    }
    return v;
}

__device__ __forceinline__ float block_reduce_max(float v) {
    const int num_warps = blockDim.x / WARP_SIZE;
    v = warp_reduce_max(v);
    __shared__ float shm[32];
    int warp_id = threadIdx.x / WARP_SIZE;
    int lane_id = threadIdx.x % WARP_SIZE;
    if (lane_id == 0) shm[warp_id] = v;
    __syncthreads();

    if (warp_id == 0) {
        v = (lane_id < num_warps) ? shm[lane_id] : -INFINITY;
        v = warp_reduce_max(v);
    }
    return v;
}

__device__ __forceinline__ float warp_reduce_sum(float v) {
#pragma unroll
    for (int mask = 16; mask > 0; mask /= 2) {
        v += __shfl_xor_sync(0xffffffff, v, mask);
    }
    return v;
}

__device__ __forceinline__ float block_reduce_sum(float v) {
    const int num_warps = blockDim.x / WARP_SIZE;
    v = warp_reduce_sum(v);
    __shared__ float shm[32];
    int warp_id = threadIdx.x / WARP_SIZE;
    int lane_id = threadIdx.x % WARP_SIZE;
    if (lane_id == 0) shm[warp_id] = v;
    __syncthreads();

    if (warp_id == 0) {
        v = (lane_id < num_warps) ? shm[lane_id] : 0.f;
        v = warp_reduce_sum(v);
    }
    return v;
}

__global__ void double_softmax_kernel(const float* input, float* output, int N, int S) {
    // First softmax pass
    float max_val1 = -INFINITY;
    for (int i = threadIdx.x; i < N; i += blockDim.x) {
        max_val1 = fmaxf(max_val1, input[i * S]);
    }
    max_val1 = block_reduce_max(max_val1);

    float sum_exp1 = 0.0f;
    float y_values[4];
    int count = 0;
    for (int i = threadIdx.x; i < N; i += blockDim.x) {
        float exp_val = expf(input[i * S] - max_val1);
        sum_exp1 += exp_val;
        if (count < 4) y_values[count++] = exp_val;
    }
    sum_exp1 = block_reduce_sum(sum_exp1);
    float inv_sum1 = 1.0f / sum_exp1;

    // Store intermediate y values
    int ptr = threadIdx.x;
    for (int i = 0; i < count; ++i) {
        y_values[i] *= inv_sum1;
        ptr += blockDim.x;
    }

    // Second softmax pass
    float max_val2 = -INFINITY;
    for (int i = 0; i < count; ++i) {
        max_val2 = fmaxf(max_val2, y_values[i]);
    }
    max_val2 = block_reduce_max(max_val2);

    float sum_exp2 = 0.0f;
    for (int i = 0; i < count; ++i) {
        sum_exp2 += expf(y_values[i] - max_val2);
    }
    sum_exp2 = block_reduce_sum(sum_exp2);
    float inv_sum2 = 1.0f / sum_exp2;

    // Write final output
    ptr = threadIdx.x;
    for (int i = 0; i < count; ++i) {
        if (ptr < N) {
            output[ptr * S] = y_values[i] * inv_sum2;
            ptr += blockDim.x;
        }
    }
}

torch::Tensor double_softmax_cuda(torch::Tensor input, int dim) {
    int N = input.size(dim);
    int S = input.stride(dim);
    torch::Tensor output = torch::empty_like(input);
    int64_t num_vectors = input.numel() / N;
    const int block_size = 256;
    double_softmax_kernel<<<num_vectors, block_size>>>(
        input.const_data_ptr<float>(),
        output.mutable_data_ptr<float>(),
        N,
        S
    );
    return output;
}
