__global__ void fused_sigmoid_relu_add_bias_kernel(
    const float* input, 
    const float* bias,
    float* output,
    int batch_size,
    int in_channels,
    int height,
    int width,
    int total_elements
) {
    const int index = blockIdx.x * blockDim.x + threadIdx.x;
    if (index >= total_elements) return;

    // Calculate 4D tensor indices
    const int elements_per_channel = height * width;
    const int elements_per_batch = in_channels * elements_per_channel;

    const int b = index / elements_per_batch;
    const int c = (index % elements_per_batch) / elements_per_channel;
    const int spatial_idx = index % elements_per_channel;

    const float val = input[index];
    const float sigmoid = 1.0f / (1.0f + expf(-val));
    const float relu = fmaxf(sigmoid, 0.0f);
    output[index] = relu + bias[c];
}

