__global__ void meshgrid_ge_kernel(const float* x, const float* y, bool* output, int M, int N) {
    const int i = blockIdx.x * blockDim.x + threadIdx.x;
    const int j = blockIdx.y * blockDim.y + threadIdx.y;

    if (i < M && j < N) {
        output[i * N + j] = x[i] >= y[j];
