import torch
import torch.nn as nn
from torch.utils.cpp_extension import load_inline

# CUDA kernel and C++ wrapper for fused permute and logical_or with roll
source = """
#include <torch/extension.h>

__global__ void permute_logical_or_kernel(
    const float *input,
    bool *output,
    int64_t s0, int64_t s1, int64_t s2, int64_t s3,
    int64_t st0, int64_t st1, int64_t st2, int64_t st3,
    int64_t logical_or_dim
) {
    int64_t idx = blockIdx.x * blockDim.x + threadIdx.x;
    if (idx >= s0 * s1 * s2 * s3) return;

    // Calculate 4D indices
    int64_t i0 = idx / (s1 * s2 * s3);
    int64_t remainder = idx % (s1 * s2 * s3);
    int64_t i1 = remainder / (s2 * s3);
    remainder %= (s2 * s3);
    int64_t i2 = remainder / s3;
    int64_t i3 = remainder % s3;

    // Original linear index
    int64_t linear_idx = i0 * st0 + i1 * st1 + i2 * st2 + i3 * st3;

    // Roll along specified dimension
    int64_t rolled_dim;
    switch(logical_or_dim) {
        case 0: rolled_dim = (i0 - 1 + s0) % s0; break;
        case 1: rolled_dim = (i1 - 1 + s1) % s1; break;
        case 2: rolled_dim = (i2 - 1 + s2) % s2; break;
        default: rolled_dim = (i3 - 1 + s3) % s3; break;
    }

    // Compute rolled index
    int64_t rolled_linear_idx = 
        (logical_or_dim == 0 ? rolled_dim : i0) * st0 +
        (logical_or_dim == 1 ? rolled_dim : i1) * st1 +
        (logical_or_dim == 2 ? rolled_dim : i2) * st2 +
        (logical_or_dim == 3 ? rolled_dim : i3) * st3;

    output[idx] = (input[linear_idx] != 0.0f) || (input[rolled_linear_idx] != 0.0f);
}

torch::Tensor permute_logical_or_cuda(torch::Tensor input, std::vector<int64_t> permute_dims, int64_t logical_or_dim) {
    TORCH_CHECK(input.dim() == 4, "Input must be 4D tensor");

    // Compute permuted sizes/strides
    auto input_sizes = input.sizes().vec();
    auto input_strides = input.strides().vec();
    std::vector<int64_t> p_sizes, p_strides;
    for (auto dim : permute_dims) {
        p_sizes.push_back(input_sizes[dim]);
        p_strides.push_back(input_strides[dim]);
    }

    // Create output tensor
    auto output = torch::empty(p_sizes, input.options().dtype(torch::kBool));

    // Launch kernel
    int64_t total_elements = output.numel();
    const int64_t block_size = 256;
    permute_logical_or_kernel<<<(total_elements + block_size - 1)/block_size, block_size>>>(
        input.data_ptr<float>(),
        output.data_ptr<bool>(),
        p_sizes[0], p_sizes[1], p_sizes[2], p_sizes[3],
        p_strides[0], p_strides[1], p_strides[2], p_strides[3],
        logical_or_dim
    );

    return output;
}
