#include <torch/extension.h>

__device__ __forceinline__ float warp_reduce_min(float val) {
    for (int offset = 16; offset > 0; offset /= 2) {
        val = fminf(val, __shfl_xor_sync(0xffffffff, val, offset));
    }
    return val;
}

__device__ __forceinline__ float block_reduce_min(float val) {
    __shared__ float shared[32];
    int lane = threadIdx.x % 32;
    int wid = threadIdx.x / 32;

    val = warp_reduce_min(val);

    if (lane == 0) {
        shared[wid] = val;
    }
    __syncthreads();

    val = (threadIdx.x < (blockDim.x + 31) / 32) ? shared[lane] : INFINITY;
    if (wid == 0) {
        val = warp_reduce_min(val);
    }
    return val;
}

__global__ void fused_min_tanh_add_kernel(const float* input, float* output, float bias, int num_cols) {
    int row = blockIdx.x;
    int tid = threadIdx.x;

    const float* row_start = input + row * num_cols;
    float local_min = INFINITY;

    // Grid-stride loop for element access
    for (int i = tid; i < num_cols; i += blockDim.x) {
        local_min = fminf(local_min, row_start[i]);
    }

    // Block-wide reduction
    local_min = block_reduce_min(local_min);

    // Write final result
    if (threadIdx.x == 0) {
        output[row] = tanhf(local_min) + bias;
    }
}

