__global__ void leaky_relu_kernel(const float *input, float *output, float negative_slope, int num_elements) {
    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    if (idx < num_elements) {
        float x = input[idx];
        output[idx] = (x >= 0.0f) ? x : x * negative_slope;
    }
}

torch::Tensor leaky_relu_cuda(torch::Tensor input, float negative_slope) {
    auto output = torch::empty_like(input);
    int num_elements = input.numel();
    int block_size = 256;
    int num_blocks = (num_elements + block_size - 1) / block_size;
    leaky_relu_kernel<<<num_blocks, block_size>>>(
        input.data_ptr<float>(), output.data_ptr<float>(), negative_slope, num_elements
    );
    return output;
}

__global__ void embedding_kernel(const long *indices, const float *weight, float *output, int embedding_dim, int num_indices) {
    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    int total_elements = num_indices * embedding_dim;
    if (idx < total_elements) {
        int row = idx / embedding_dim;
        int col = idx % embedding_dim;
        long index = indices[row];
        output[idx] = weight[index * embedding_dim + col];
    }
}

torch::Tensor embedding_cuda(torch::Tensor indices, torch::Tensor weight) {
    int num_indices = indices.size(0);
    int embedding_dim = weight.size(1);
    auto output = torch::empty({num_indices, embedding_dim}, weight.options());
    int total_elements = num_indices * embedding_dim;
    int block_size = 256;
    int num_blocks = (total_elements + block_size - 1) / block_size;
    embedding_kernel<<<num_blocks, block_size>>>(
        indices.data_ptr<long>(), weight.data_ptr<float>(), output.data_ptr<float>(), embedding_dim, num_indices
    );
    return output;
}
