source = """
#include <torch/extension.h>

__global__ void fused_tanh_cumsum_kernel(const float* input, float* output, 
                                        int batch_size, int channels, 
                                        int height, int width) {
    // Calculate 3D grid coordinates from blockIdx.x
    int batch = blockIdx.x / (channels * width);
    int residual = blockIdx.x % (channels * width);
    int channel = residual / width;
    int w = residual % width;

    float sum = 0.0f;
    for (int h = 0; h < height; ++h) {
        // Calculate linear index for NHWC layout (channel-major)
        int index = batch * channels * height * width + 
                   channel * height * width +
                   h * width + w;

        float val = input[index];
        float tanh_val = tanhf(val);
        sum += tanh_val;
        output[index] = sum;
    }
}

torch::Tensor fused_tanh_cumsum_cuda(torch::Tensor input) {
    TORCH_CHECK(input.dim() == 4, "Input must be 4D");
    auto sizes = input.sizes();
    int batch_size = sizes[0];
    int channels = sizes[1];
    int height = sizes[2];
    int width = sizes[3];

    auto output = torch::empty_like(input);

    // Total blocks = batch * channels * width (1 block per w-channel-batch)
    int num_blocks = batch_size * channels * width;
    int block_size = 1;  // Each block processes entire height dimension

    fused_tanh_cumsum_kernel<<<num_blocks, block_size>>>(
        input.const_data_ptr<float>(),
        output.mutable_data_ptr<float>(),
        batch_size, channels, height, width
    );

    return output;
}
