import torch
import torch.nn as nn
from torch.utils.cpp_extension import load_inline

# CUDA code for fused LeakyReLU and Softmax
source = """
#include <torch/extension.h>
#include <cmath>

#define WARP_SIZE 32

__device__ __forceinline__ float warp_reduce_max(float v) {
#pragma unroll
    for (int mask = 16; mask > 0; mask /= 2) {
        v = fmaxf(v, __shfl_xor_sync(0xffffffff, v, mask));
    }
    return v;
}

__device__ __forceinline__ float block_reduce_max(float v) {
    const int num_warps = blockDim.x / WARP_SIZE;
    v = warp_reduce_max(v);
    __shared__ float shm[32];
    const int warp_id = threadIdx.x / WARP_SIZE;
    const int lane_id = threadIdx.x % WARP_SIZE;
    if (lane_id == 0) {
        shm[warp_id] = v;
    }
    __syncthreads();
    v = (lane_id < num_warps) ? shm[lane_id] : -INFINITY;
    v = warp_reduce_max(v);
    return v;
}

__device__ __forceinline__ float warp_reduce_sum(float v) {
#pragma unroll
    for (int mask = 16; mask > 0; mask /= 2) {
        v += __shfl_xor_sync(0xffffffff, v, mask);
    }
    return v;
}

__device__ __forceinline__ float block_reduce_sum(float v) {
    const int num_warps = blockDim.x / WARP_SIZE;
    v = warp_reduce_sum(v);
    __shared__ float shm[32];
    const int warp_id = threadIdx.x / WARP_SIZE;
    const int lane_id = threadIdx.x % WARP_SIZE;
    if (lane_id == 0) {
        shm[warp_id] = v;
    }
    __syncthreads();
    v = (lane_id < num_warps) ? shm[lane_id] : 0.0f;
    v = warp_reduce_sum(v);
    return v;
}

__global__ void fused_leaky_relu_softmax_kernel(
    const float* input, float* output, float negative_slope, int N, int S
) {
    const int tile_offset = (blockIdx.x - blockIdx.x % S) * N + blockIdx.x % S;
    const float* input_tile = input + tile_offset;
    float* output_tile = output + tile_offset;

    float max_val = -INFINITY;
    for (int i = threadIdx.x; i < N; i += blockDim.x) {
        float val = input_tile[i * S];
        val = val > 0 ? val : val * negative_slope;
        output_tile[i * S] = val;
        max_val = fmaxf(max_val, val);
    }
    max_val = block_reduce_max(max_val);

    float sum = 0.0f;
    for (int i = threadIdx.x; i < N; i += blockDim.x) {
        float val = output_tile[i * S] - max_val;
        float exp_val = expf(val);
        output_tile[i * S] = exp_val;
        sum += exp_val;
    }
    sum = block_reduce_sum(sum);
    float inv_sum = 1.0f / sum;

    for (int i = threadIdx.x; i < N; i += blockDim.x) {
        output_tile[i * S] *= inv_sum;
    }
}

torch::Tensor fused_leaky_relu_softmax_cuda(
    torch::Tensor input, float negative_slope, int64_t dim
) {
    int64_t N = input.size(dim);
    int64_t S = input.stride(dim);
    torch::Tensor output = torch::empty_like(input);
    int64_t grid_size = input.numel() / N;
    const int block_size = 256;
    fused_leaky_relu_softmax_kernel<<<grid_size, block_size>>>(
        input.const_data_ptr<float>(),
        output.mutable_data_ptr<float>(),
        negative_slope,
        N,
        S
    );
    return output;
}
"""

