import torch
import torch.nn as nn
from torch.utils.cpp_extension import load_inline

source = """
#include <torch/extension.h>
#include <cmath>

__global__ void pad_and_log_softmax_kernel(
    const float *input,
    float *output,
    const int batch_size,
    const int C,
    const int H,
    const int W,
    const int H_padded,
    const int W_padded,
    const int pad_top,
    const int pad_left,
    const int pad_bottom,
    const int pad_right) {

    const int total_positions = batch_size * H_padded * W_padded;
    int tid = blockIdx.x * blockDim.x + threadIdx.x;
    if (tid >= total_positions) return;

    int batch = tid / (H_padded * W_padded);
    int hw = tid % (H_padded * W_padded);
    int h_padded = hw / W_padded;
    int w_padded = hw % W_padded;

    int h_in = h_padded - pad_top;
    int w_in = w_padded - pad_left;

    bool h_valid = (h_in >= 0) && (h_in < H);
    bool w_valid = (w_in >= 0) && (w_in < W);
    bool is_padded = !(h_valid && w_valid);

    int base_output_idx = batch * C * H_padded * W_padded + h_padded * W_padded + w_padded;

    if (is_padded) {
        float logC = logf(static_cast<float>(C));
        for (int c = 0; c < C; ++c) {
            output[base_output_idx + c * H_padded * W_padded] = -logC;
        }
        return;
    }

    int base_input_idx = batch * C * H * W + h_in * W + w_in;

    float max_val = -INFINITY;
    for (int c = 0; c < C; ++c) {
        int input_idx = base_input_idx + c * H * W;
        float val = input[input_idx];
        if (val > max_val) max_val = val;
    }

    float sum_exp = 0.0f;
    for (int c = 0; c < C; ++c) {
        int input_idx = base_input_idx + c * H * W;
        float val = input[input_idx];
        sum_exp += expf(val - max_val);
    }
    float log_sum_exp = logf(sum_exp);

    for (int c = 0; c < C; ++c) {
        int input_idx = base_input_idx + c * H * W;
        float val = input[input_idx];
        output[base_output_idx + c * H_padded * W_padded] = val - max_val - log_sum_exp;
    }
}

torch::Tensor pad_and_log_softmax_cuda(
    torch::Tensor input,
    std::vector<int64_t> padding_shape,
    int log_softmax_dim) {

    TORCH_CHECK(log_softmax_dim == 1, "log_softmax must be applied along the channel dimension (dim=1)");
    TORCH_CHECK(padding_shape.size() == 4, "padding_shape must have 4 elements (pad_left, pad_right, pad_top, pad_bottom)");

    int pad_left = padding_shape[0];
    int pad_right = padding_shape[1];
    int pad_top = padding_shape[2];
    int pad_bottom = padding_shape[3];

    int batch_size = input.size(0);
    int C = input.size(1);
    int H = input.size(2);
    int W = input.size(3);

    int H_padded = H + pad_top + pad_bottom;
    int W_padded = W + pad_left + pad_right;

    auto output = torch::empty({batch_size, C, H_padded, W_padded}, input.options());

    int total_positions = batch_size * H_padded * W_padded;
    const int block_size = 256;
    int grid_size = (total_positions + block_size - 1) / block_size;

    pad_and_log_softmax_kernel<<<grid_size, block_size>>>(
        input.data_ptr<float>(),
        output.data_ptr<float>(),
        batch_size,
        C,
        H,
        W,
        H_padded,
        W_padded,
        pad_top,
        pad_left,
        pad_bottom,
        pad_right
    );

    return output;
}
"""

cpp_src = """
torch::Tensor pad_and_log_softmax_cuda(torch::Tensor input, std::vector<int64_t> padding_shape, int log_softmax_dim);
"""

ext = load_inline(
    name='pad_log_softmax',
    cpp_sources=cpp_src,
    cuda_sources=source,
    functions=['pad_and_log_softmax_cuda'],
    verbose=True,
