    def __init__(self, padding_shape, log_softmax_dim):
        super().__init__()
        self.padding_shape = padding_shape
        self.log_softmax_dim = log_softmax_dim

    def forward(self, x):
        return ext.pad_and_log_softmax_cuda(x, self.padding_shape, self.log_softmax_dim)

