#include <torch/extension.h>

__global__ void all_and_multiply_kernel(
    const float* input, float* output, float factor,
    int N, int C, int H, int W,
    int input_stride_n, int input_stride_c, int input_stride_h, int input_stride_w,
    int output_stride_n, int output_stride_h, int output_stride_w
) {
    int index = blockIdx.x * blockDim.x + threadIdx.x;
    int total = N * H * W;
    if (index >= total) return;

    int n = index / (H * W);
    int hw = index % (H * W);
    int h = hw / W;
    int w = hw % W;

    bool all_nonzero = true;
    for (int c = 0; c < C; ++c) {
        int input_idx = n * input_stride_n + c * input_stride_c + h * input_stride_h + w * input_stride_w;
        if (input[input_idx] == 0.0f) {
            all_nonzero = false;
            break;
        }
    }

    int output_idx = n * output_stride_n + h * output_stride_h + w * output_stride_w;
    output[output_idx] = all_nonzero ? factor : 0.0f;
}

