source = """
#include <torch/extension.h>

__global__ void rsqrt_pad_kernel(
    const float* input, float* output,
    int batch_size, int channels,
    int orig_h, int orig_w,
    int pad_l, int pad_r, int pad_t, int pad_b,
    float value
) {
    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    int total = batch_size * channels * (orig_h + pad_t + pad_b) * (orig_w + pad_l + pad_r);
    if (idx >= total) return;

    // Compute 4D indices (N, C, H, W) for output
    int n = idx / (channels * (orig_h + pad_t + pad_b) * (orig_w + pad_l + pad_r));
    int rem = idx % (channels * (orig_h + pad_t + pad_b) * (orig_w + pad_l + pad_r));
    int c = rem / ((orig_h + pad_t + pad_b) * (orig_w + pad_l + pad_r));
    rem %= ((orig_h + pad_t + pad_b) * (orig_w + pad_l + pad_r));
    int h = rem / (orig_w + pad_l + pad_r);
    int w = rem % (orig_w + pad_l + pad_r);

    if (h < pad_t || h >= orig_h + pad_t || w < pad_l || w >= orig_w + pad_l) {
        output[idx] = value;
    } else {
        // Compute input indices
        int h_in = h - pad_t;
        int w_in = w - pad_l;
        // Input is contiguous after .contiguous() call
        int input_idx = n * channels * orig_h * orig_w +
                       c * orig_h * orig_w +
                       h_in * orig_w +
                       w_in;
        output[idx] = rsqrtf(input[input_idx]);
    }
}

torch::Tensor fused_rsqrt_pad_cuda(
    torch::Tensor input,
    int pad_l, int pad_r, int pad_t, int pad_b,
    float value
) {
    auto input_contig = input.contiguous();
    const float* input_ptr = input_contig.const_data_ptr<float>();

    int batch = input_contig.size(0);
    int ch = input_contig.size(1);
    int h = input_contig.size(2);
    int w = input_contig.size(3);

    auto output = torch::empty({batch, ch, h + pad_t + pad_b, w + pad_l + pad_r}, input_contig.options());
    float* out_ptr = output.mutable_data_ptr<float>();

    int total = output.numel();
    int block = 256;
    int grid = (total + block - 1) / block;

    rsqrt_pad_kernel<<<grid, block>>>(
        input_ptr, out_ptr,
        batch, ch, h, w,
        pad_l, pad_r, pad_t, pad_b,
        value
    );

    return output;
}
