# Define CUDA kernel for fused unbind and division
source = """
#include <torch/extension.h>

__global__ void unbind_div_kernel(
    const float* input,
    float* output,
    int B,
    int H,
    int W,
    int input_stride_b,
    int input_stride_c,
    int input_stride_h,
    int input_stride_w,
    int output_stride_b,
    int output_stride_h,
    int output_stride_w
) {
    int index = blockIdx.x * blockDim.x + threadIdx.x;
    if (index >= B * H * W) return;

    int b = index / (H * W);
    int remaining = index % (H * W);
    int h = remaining / W;
    int w = remaining % W;

    int input0_offset = b * input_stride_b + 0 * input_stride_c + h * input_stride_h + w * input_stride_w;
    int input1_offset = b * input_stride_b + 1 * input_stride_c + h * input_stride_h + w * input_stride_w;
    int output_offset = b * output_stride_b + h * output_stride_h + w * output_stride_w;

    output[output_offset] = input[input0_offset] / input[input1_offset];
}

torch::Tensor unbind_div_cuda(torch::Tensor input) {
    TORCH_CHECK(input.size(1) == 2, "Input must have exactly 2 channels");
    auto sizes = input.sizes();
    torch::Tensor output = torch::empty({sizes[0], sizes[2], sizes[3]}, input.options());

    int B = input.size(0);
    int H = input.size(2);
    int W = input.size(3);
    auto input_strides = input.strides();
    auto output_strides = output.strides();

    int num_elements = B * H * W;
    const int block_size = 256;
    int grid_size = (num_elements + block_size - 1) / block_size;

    unbind_div_kernel<<<grid_size, block_size>>>(
        input.const_data_ptr<float>(),
        output.mutable_data_ptr<float>(),
        B, H, W,
        input_strides[0], input_strides[1], input_strides[2], input_strides[3],
        output_strides[0], output_strides[1], output_strides[2]
    );

    return output;
}
