import torch
import torch.nn as nn
from torch.utils.cpp_extension import load_inline

# Custom CUDA kernel for fused clip and log_softmax
source = """
#include <torch/extension.h>
#include <cuda.h>
#include <cuda_runtime.h>
#include <cmath>

#define WARP_SIZE 32

__device__ __forceinline__ float warp_reduce_max(float val) {
    for (int offset = WARP_SIZE / 2; offset > 0; offset /= 2) {
        val = fmaxf(val, __shfl_xor_sync(0xffffffff, val, offset));
    }
    return val;
}

__device__ __forceinline__ float warp_reduce_sum(float val) {
    for (int offset = WARP_SIZE / 2; offset > 0; offset /= 2) {
        val += __shfl_xor_sync(0xffffffff, val, offset);
    }
    return val;
}

__global__ void fused_clip_log_softmax_kernel(
    const float* input, float* output, float clip_value,
    int dim_size, int outer_size
) {
    extern __shared__ float s_data[];
    int outer_idx = blockIdx.x;
    int tid = threadIdx.x;

    if (outer_idx >= outer_size) return;

    const float* input_slice = input + outer_idx * dim_size;
    float* output_slice = output + outer_idx * dim_size;

    // Load and clip into shared memory
    for (int i = tid; i < dim_size; i += blockDim.x) {
        float val = input_slice[i];
        s_data[i] = fminf(val, clip_value);
    }
    __syncthreads();

    // Compute max value
    float max_val = -INFINITY;
    for (int i = tid; i < dim_size; i += blockDim.x) {
        max_val = fmaxf(max_val, s_data[i]);
    }
    max_val = warp_reduce_max(max_val);
    __syncthreads();

    // Compute sum of exponents
    float sum = 0.0f;
    for (int i = tid; i < dim_size; i += blockDim.x) {
        sum += expf(s_data[i] - max_val);
    }
    sum = warp_reduce_sum(sum);
    float log_sum = logf(sum);

    // Compute final output
    for (int i = tid; i < dim_size; i += blockDim.x) {
        output_slice[i] = s_data[i] - max_val - log_sum;
    }
}

torch::Tensor fused_clip_log_softmax_cuda(
    torch::Tensor input, float clip_value, int log_softmax_dim
) {
    auto input_sizes = input.sizes();
    int64_t dim = log_softmax_dim;
    int64_t dim_size = input.size(dim);
    int64_t outer_size = 1;

    for (int i = 0; i < input_sizes.size(); ++i) {
        if (i != dim) outer_size *= input_sizes[i];
    }

    auto input_2d = input.view({outer_size, dim_size});
    auto output_2d = torch::empty_like(input_2d);

    int block_size = 256;
    int grid_size = outer_size;
    size_t shared_mem_size = dim_size * sizeof(float);

    fused_clip_log_softmax_kernel<<<grid_size, block_size, shared_mem_size>>>(
        input_2d.contiguous().data_ptr<float>(),
        output_2d.data_ptr<float>(),
        clip_value,
        dim_size,
        outer_size
    );

    return output_2d.view(input_sizes);
}
