# CUDA code for the linear layer and logical OR operation
source = """
#include <ATen/cuda/CUDAContext.h>
#include <c10/cuda/CUDACachingAllocator.h>
#include <torch/extension.h>
#include <cublasLt.h>

#define CHECK_CUBLAS(status) TORCH_CHECK(status == CUBLAS_STATUS_SUCCESS, "cuBLAS error")

torch::Tensor linear_cuda(torch::Tensor x, torch::Tensor weight, torch::Tensor bias) {
    int M = x.size(0);
    int K = x.size(1);
    int N = weight.size(0);

    auto output = torch::empty({M, N}, x.options());

    const float* A = weight.data_ptr<float>();
    const float* B = x.data_ptr<float>();
    const float* bias_ptr = bias.data_ptr<float>();
    float* C = output.data_ptr<float>();

    const float alpha = 1.f;
    const float beta = 0.f;

    auto handle = at::cuda::getCurrentCUDABlasLtHandle();

    cublasLtMatmulDesc_t matmul_desc;
    CHECK_CUBLAS(cublasLtMatmulDescCreate(&matmul_desc, CUBLAS_COMPUTE_32F, CUDA_R_32F));

    cublasOperation_t trans_A = CUBLAS_OP_T;
    CHECK_CUBLAS(cublasLtMatmulDescSetAttribute(matmul_desc, CUBLASLT_MATMUL_DESC_TRANSA, &trans_A, sizeof(trans_A)));
    cublasOperation_t trans_B = CUBLAS_OP_N;
    CHECK_CUBLAS(cublasLtMatmulDescSetAttribute(matmul_desc, CUBLASLT_MATMUL_DESC_TRANSB, &trans_B, sizeof(trans_B)));

    auto epilogue = CUBLASLT_EPILOGUE_BIAS;
    CHECK_CUBLAS(cublasLtMatmulDescSetAttribute(matmul_desc, CUBLASLT_MATMUL_DESC_EPILOGUE, &epilogue, sizeof(epilogue)));
    CHECK_CUBLAS(cublasLtMatmulDescSetAttribute(matmul_desc, CUBLASLT_MATMUL_DESC_BIAS_POINTER, &bias_ptr, sizeof(bias_ptr)));

    cublasLtMatrixLayout_t A_desc, B_desc, C_desc;
    CHECK_CUBLAS(cublasLtMatrixLayoutCreate(&A_desc, CUDA_R_32F, weight.size(1), N, weight.stride(0)));
    CHECK_CUBLAS(cublasLtMatrixLayoutCreate(&B_desc, CUDA_R_32F, K, M, x.stride(0)));
    CHECK_CUBLAS(cublasLtMatrixLayoutCreate(&C_desc, CUDA_R_32F, N, M, output.stride(0)));

    const size_t workspace_size = 1024 * 1024;
    auto workspace = c10::cuda::CUDACachingAllocator::get()->allocate(workspace_size);

    CHECK_CUBLAS(cublasLtMatmul(handle, matmul_desc, &alpha, A, A_desc, B, B_desc, &beta, C, C_desc, C, C_desc,
                                nullptr, workspace.get(), workspace_size, at::cuda::getCurrentCUDAStream()));

    cublasLtMatmulDescDestroy(matmul_desc);
    cublasLtMatrixLayoutDestroy(A_desc);
    cublasLtMatrixLayoutDestroy(B_desc);
    cublasLtMatrixLayoutDestroy(C_desc);

    return output;
}

__global__ void logical_or_kernel(const float* linear_out, const float* model_bias, bool* output, int batch_size, int out_features) {
    int idx = blockIdx.x * blockDim.x + threadIdx.x;
